import { vi } from "vitest";
import { ArticleList } from "../../../src/components/article-list";
import {
  DEFAULT_SETTINGS,
  type FeedItem,
  type RssDashboardSettings,
} from "../../../src/types/types";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

type ArticleListCallbacks = ConstructorParameters<typeof ArticleList>[6];

export interface ArticleListHarnessOverrides {
  container?: HTMLElement;
  settings?: Partial<RssDashboardSettings>;
  callbacks?: Partial<ArticleListCallbacks>;
  articles?: FeedItem[];
  selectedArticle?: FeedItem | null;
  title?: string;
  titleTooltip?: string | null;
  currentPage?: number;
  totalPages?: number;
  pageSize?: number;
  totalArticles?: number;
  statusFilters?: Set<string>;
  tagFilters?: Set<string>;
  filterLogic?: "AND" | "OR";
  currentFeedUrl?: string | null;
  showFeedSource?: boolean;
}

function cloneSettings(): RssDashboardSettings {
  return JSON.parse(JSON.stringify(DEFAULT_SETTINGS)) as RssDashboardSettings;
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (!value || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends Record<string, unknown>>(
  target: T,
  source: Record<string, unknown>,
): T {
  for (const [key, sourceValue] of Object.entries(source)) {
    const targetValue = (target as Record<string, unknown>)[key];
    if (isPlainObject(targetValue) && isPlainObject(sourceValue)) {
      deepMerge(targetValue, sourceValue);
      continue;
    }
    (target as Record<string, unknown>)[key] = sourceValue;
  }
  return target;
}

function installCssEscapePolyfill(): void {
  if (typeof (window as any).CSS === "undefined") {
    (window as any).CSS = {
      escape: (s: string) => s.replace(/([^\w-])/g, "\\$1"),
    };
  } else if (typeof (window as any).CSS.escape === "undefined") {
    (window as any).CSS.escape = (s: string) => s.replace(/([^\w-])/g, "\\$1");
  }
}

export function buildArticle(overrides: Partial<FeedItem> = {}): FeedItem {
  const pubDate =
    overrides.pubDate ?? new Date("2026-01-01T00:00:00Z").toISOString();
  return {
    guid: overrides.guid ?? "guid",
    title: overrides.title ?? "Title",
    link: overrides.link ?? "https://example.com",
    pubDate,
    description: overrides.description ?? "<p>desc</p>",
    read: overrides.read ?? false,
    starred: overrides.starred ?? false,
    saved: overrides.saved ?? false,
    tags: overrides.tags ?? [],
    feedTitle: overrides.feedTitle ?? "Feed",
    feedUrl: overrides.feedUrl ?? "https://example.com/feed",
    coverImage: overrides.coverImage ?? "",
  } as FeedItem;
}

export function createArticleListHarness(overrides: ArticleListHarnessOverrides = {}) {
  installObsidianDomPolyfills();
  installCssEscapePolyfill();

  const mockRAF = (cb: FrameRequestCallback) => {
    cb(0);
    return 0;
  };
  let restoreRaf = () => {};
  try {
    const rafSpy = vi
      .spyOn(window, "requestAnimationFrame")
      .mockImplementation(mockRAF);
    restoreRaf = () => rafSpy.mockRestore();
  } catch {
    const originalRAF = window.requestAnimationFrame;
    window.requestAnimationFrame = mockRAF;
    restoreRaf = () => {
      window.requestAnimationFrame = originalRAF;
    };
  }

  const createdContainer = !overrides.container;
  const container =
    overrides.container ?? (document.body as unknown as HTMLElement).createDiv();

  const settings = cloneSettings();
  if (overrides.settings) {
    deepMerge(settings as unknown as Record<string, unknown>, overrides.settings);
  }

  const callbacks: ArticleListCallbacks = {
    onArticleClick: vi.fn(),
    onToggleViewStyle: vi.fn(),
    onRefreshFeeds: vi.fn(async () => {}),
    onSearch: vi.fn(),
    onArticleUpdate: vi.fn(),
    onArticleSave: vi.fn(),
    onToggleSidebar: vi.fn(),
    onSortChange: vi.fn(),
    onGroupChange: vi.fn(),
    onFilterChange: vi.fn(),
    onPageChange: vi.fn(),
    onPageSizeChange: vi.fn(),
    onPersistSettings: vi.fn(),
  } as ArticleListCallbacks;
  if (overrides.callbacks) {
    Object.assign(callbacks as unknown as Record<string, unknown>, overrides.callbacks);
  }

  const articles = overrides.articles ?? [];
  const selectedArticle = overrides.selectedArticle ?? null;
  const currentPage = overrides.currentPage ?? 1;
  const totalPages = overrides.totalPages ?? 1;
  const pageSize = overrides.pageSize ?? 10;
  const totalArticles = overrides.totalArticles ?? articles.length;
  const statusFilters = overrides.statusFilters ?? new Set<string>();
  const tagFilters = overrides.tagFilters ?? new Set<string>();
  const filterLogic = overrides.filterLogic ?? "OR";
  const currentFeedUrl = overrides.currentFeedUrl ?? null;
  const showFeedSource = overrides.showFeedSource ?? true;

  const list = new ArticleList(
    container,
    settings,
    overrides.title ?? "All articles",
    overrides.titleTooltip ?? null,
    articles,
    selectedArticle,
    callbacks,
    currentPage,
    totalPages,
    pageSize,
    totalArticles,
    statusFilters,
    tagFilters,
    filterLogic,
    currentFeedUrl,
    showFeedSource,
  );

  const getHeaderEl = () =>
    container.querySelector<HTMLElement>(".rss-dashboard-articles-header");
  const getArticlesListEl = () =>
    container.querySelector<HTMLElement>(".rss-dashboard-articles-list");
  const getPaginationEl = () =>
    container.querySelector<HTMLElement>(".rss-dashboard-pagination-wrapper");
  const getArticleEl = (guid: string) =>
    container.querySelector<HTMLElement>(`#article-${CSS.escape(guid)}`);
  const getVisibleArticleIds = () =>
    Array.from(
      container.querySelectorAll<HTMLElement>(
        ".rss-dashboard-article-item, .rss-dashboard-article-card, .rss-dashboard-feed-item",
      ),
    )
      .filter((el) => !el.classList.contains("rss-dashboard-search-hidden"))
      .map((el) => el.id.replace(/^article-/, ""));

  const cleanup = () => {
    restoreRaf();
    if (createdContainer) {
      container.remove();
    }
  };

  return {
    container,
    settings,
    callbacks,
    articles,
    list,
    buildArticle,
    getHeaderEl,
    getArticlesListEl,
    getPaginationEl,
    getArticleEl,
    getVisibleArticleIds,
    cleanup,
  };
}

import { afterEach, describe, expect, it, vi } from "vitest";
import { buildArticle, createArticleListHarness } from "./article-list-harness";

describe("Phase 7 - ArticleList in-place updates", () => {
  afterEach(() => {
    document.body.empty();
    vi.restoreAllMocks();
    vi.useRealTimers();
  });

  it("updateArticleInPlace should sync read/saved/starred classes and toggle titles", () => {
    const h = createArticleListHarness({
      settings: {
        viewStyle: "list",
        articleGroupBy: "none",
        articleSort: "newest",
        display: {
          mobileListToolbarStyle: "left-grid",
        } as any,
      },
      articles: [
        buildArticle({
          guid: "1",
          title: "One",
          read: false,
          saved: false,
          starred: false,
        }),
      ],
    });
    h.list.render();

    const articleEl = h.getArticleEl("1");
    expect(articleEl).not.toBeNull();
    expect(articleEl?.classList.contains("unread")).toBe(true);
    expect(articleEl?.classList.contains("saved")).toBe(false);
    expect(articleEl?.classList.contains("unstarred")).toBe(true);

    const readToggle = articleEl?.querySelector<HTMLElement>(
      ".rss-dashboard-read-toggle",
    );
    const saveToggle = articleEl?.querySelector<HTMLElement>(
      ".rss-dashboard-save-toggle",
    );
    const starToggle = articleEl?.querySelector<HTMLElement>(
      ".rss-dashboard-star-toggle",
    );

    expect(readToggle?.getAttribute("title")).toBe("Mark as read");
    expect(saveToggle?.getAttribute("title")).toContain("Save");
    expect(starToggle?.getAttribute("title")).toBe("Add to starred items");

    h.list.updateArticleInPlace({
      ...h.articles[0],
      read: true,
      saved: true,
      starred: true,
    });

    expect(articleEl?.classList.contains("read")).toBe(true);
    expect(articleEl?.classList.contains("unread")).toBe(false);
    expect(articleEl?.classList.contains("saved")).toBe(true);
    expect(articleEl?.classList.contains("starred")).toBe(true);
    expect(articleEl?.classList.contains("unstarred")).toBe(false);

    expect(readToggle?.getAttribute("title")).toBe("Mark as unread");
    expect(saveToggle?.getAttribute("title")).toBe(
      "Click to open saved article",
    );
    expect(starToggle?.getAttribute("title")).toBe("Remove from starred items");

    h.cleanup();
  });

  it("syncVisibleArticlesFromSource should refresh tag colors for cloned visible articles", () => {
    const visibleArticle = buildArticle({
      guid: "1",
      title: "One",
      tags: [{ name: "tag1", color: "#000000" }],
    });
    const backingArticle = buildArticle({
      guid: "1",
      title: "One",
      tags: [{ name: "tag1", color: "#ff0000" }],
    });

    const h = createArticleListHarness({
      settings: {
        viewStyle: "card",
        articleGroupBy: "none",
        articleSort: "newest",
      },
      articles: [visibleArticle],
    });
    h.list.render();

    const articleEl = h.getArticleEl("1");
    const tagEl = articleEl?.querySelector<HTMLElement>(
      ".rss-dashboard-article-tag",
    );
    expect(tagEl?.style.getPropertyValue("--tag-color")).toBe("#000000");

    h.list.syncVisibleArticlesFromSource(() => backingArticle);
    h.list.refreshVisibleArticleTags();

    const updatedTagEl = h
      .getArticleEl("1")
      ?.querySelector<HTMLElement>(".rss-dashboard-article-tag");
    expect(updatedTagEl?.style.getPropertyValue("--tag-color")).toBe("#ff0000");

    h.cleanup();
  });

  it("removeArticleInPlace should remove the element after the timeout and restore scrollTop", () => {
    vi.useFakeTimers();

    const h = createArticleListHarness({
      settings: {
        viewStyle: "list",
        articleGroupBy: "none",
        articleSort: "newest",
      },
      articles: [
        buildArticle({ guid: "1", title: "One" }),
        buildArticle({ guid: "2", title: "Two" }),
      ],
    });
    h.list.render();

    const listEl = h.getArticlesListEl();
    expect(listEl).not.toBeNull();
    if (!listEl) throw new Error("Expected articles list element");
    listEl.scrollTop = 123;

    expect(h.getArticleEl("1")).not.toBeNull();
    h.list.removeArticleInPlace("1");

    expect(h.list.hasArticle("1")).toBe(false);
    expect(h.getArticleEl("1")).not.toBeNull();

    vi.advanceTimersByTime(319);
    expect(h.getArticleEl("1")).not.toBeNull();

    vi.advanceTimersByTime(1);
    expect(h.getArticleEl("1")).toBeNull();
    expect(listEl.scrollTop).toBe(123);

    h.cleanup();
  });

  it("mark-all fallback should mutate articles, persist settings, and rerender (read)", () => {
    const h = createArticleListHarness({
      settings: {
        viewStyle: "list",
        articleGroupBy: "none",
        articleSort: "newest",
      },
      callbacks: {
        onMarkAllAsRead: undefined,
        onPersistSettings: vi.fn(),
      },
      articles: [
        buildArticle({ guid: "1", title: "One", read: false }),
        buildArticle({ guid: "2", title: "Two", read: false }),
      ],
    });
    h.list.render();

    const btn = h.container.querySelector<HTMLButtonElement>(
      "button.rss-dashboard-mark-read",
    );
    expect(btn).not.toBeNull();
