import { beforeEach, describe, expect, it, vi, afterEach } from "vitest";
import { FolderSelectorPopup } from "../../../src/components/folder-selector-popup";
import { DEFAULT_SETTINGS, type Folder, type RssDashboardSettings } from "../../../src/types/types";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

function cloneSettings(): RssDashboardSettings {
  return JSON.parse(JSON.stringify(DEFAULT_SETTINGS)) as RssDashboardSettings;
}

function createFolders(): Folder[] {
  return [
    { name: "Alpha", subfolders: [] },
    {
      name: "Zeta",
      subfolders: [{ name: "Child", subfolders: [] }],
    },
  ];
}

function createPluginStub(folders: Folder[] = createFolders()): any {
  const settings = cloneSettings();
  settings.folders = folders;
  return { settings };
}

function setViewport(width: number, height: number): void {
  Object.defineProperty(window, "innerWidth", { value: width, configurable: true });
  Object.defineProperty(window, "innerHeight", { value: height, configurable: true });
}

beforeEach(() => {
  installObsidianDomPolyfills();
  document.body.empty();
  setViewport(800, 600);
});

afterEach(() => {
  vi.useRealTimers();
  vi.restoreAllMocks();
});

describe("FolderSelectorPopup", () => {
  it("positions below the anchor by default", () => {
    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 10,
      top: 10,
      bottom: 30,
      right: 110,
      width: 100,
      height: 20,
    } as DOMRect);

    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
    });

    const popup = document.body.querySelector(
      ".rss-folder-selector-popup",
    ) as HTMLElement | null;
    expect(popup).not.toBeNull();
    expect(popup!.style.left).toBe("10px");
    expect(popup!.style.top).toBe("34px");
    expect(popup!.classList.contains("rss-folder-selector-popup-above")).toBe(
      false,
    );
  });

  it("clamps left and flips above when near viewport edges", () => {
    setViewport(300, 220);

    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 200,
      top: 180,
      bottom: 200,
      right: 260,
      width: 60,
      height: 20,
    } as DOMRect);

    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
    });

    const popup = document.body.querySelector(
      ".rss-folder-selector-popup",
    ) as HTMLElement;
    // width=240, margin=16 => maxLeft = 300 - 240 - 16 = 44
    expect(popup.style.left).toBe("44px");
    // flipped above => top = rect.top - 4
    expect(popup.style.top).toBe("176px");
    expect(popup.classList.contains("rss-folder-selector-popup-above")).toBe(
      true,
    );
  });

  it("prioritizes defaultFolder to the top when it exists (case-insensitive)", () => {
    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      defaultFolder: "zeta",
      onSelect: () => {},
    });

    const firstItemText = document.body.querySelector(
      ".rss-folder-selector-item .rss-folder-selector-text",
    )?.textContent;
    expect(firstItemText).toBe("Zeta");
  });

  it("filters folders and toggles the clear button on input", () => {
    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
    });

    const input = document.body.querySelector(
      ".rss-folder-selector-input",
    ) as HTMLInputElement;
    const clearBtn = document.body.querySelector(
      ".rss-folder-selector-clear",
    ) as HTMLElement;

    expect(clearBtn.classList.contains("is-hidden")).toBe(true);

    input.value = "child";
    input.dispatchEvent(new Event("input"));

    expect(clearBtn.classList.contains("is-hidden")).toBe(false);
    const items = Array.from(
      document.body.querySelectorAll(".rss-folder-selector-item"),
    );
    // Create option + 1 matching item (Zeta/Child)
    expect(items.length).toBe(2);
    expect(items[1].textContent).toContain("Zeta/Child");

    // Clear via button resets filter + hides button
    clearBtn.click();
    expect(input.value).toBe("");
    expect(clearBtn.classList.contains("is-hidden")).toBe(true);
    expect(
      document.body.querySelectorAll(".rss-folder-selector-item").length,
    ).toBeGreaterThan(1);
  });

  it("sanitizes forbidden characters in real-time and removes invalid highlight after timeout", () => {
    vi.useFakeTimers();

    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
    });

    const input = document.body.querySelector(
      ".rss-folder-selector-input",
    ) as HTMLInputElement;

    input.value = '  ..A*B?C|  ';
    input.dispatchEvent(new Event("input"));

    expect(input.value).toBe("ABC");
    expect(
      input.classList.contains("rss-folder-selector-input-invalid"),
    ).toBe(true);

    vi.advanceTimersByTime(500);
    expect(
      input.classList.contains("rss-folder-selector-input-invalid"),
    ).toBe(false);
  });

  it("creates a new folder option for a non-matching query and selects sanitized text", () => {
    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    const onSelect = vi.fn();
    const onClose = vi.fn();
    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect,
      onClose,
    });

    const input = document.body.querySelector(
      ".rss-folder-selector-input",
    ) as HTMLInputElement;
    input.value = "  ..New:Folder..  ";
    input.dispatchEvent(new Event("input"));

    const createItem = document.body.querySelector(
      ".rss-folder-selector-item.rss-folder-selector-create",
    ) as HTMLElement;
    expect(createItem).not.toBeNull();

    createItem.click();
    expect(onSelect).toHaveBeenCalledWith("NewFolder");
    expect(onClose).toHaveBeenCalledTimes(1);
    expect(
      document.body.querySelector(".rss-folder-selector-popup"),
    ).toBeNull();
  });

  it("supports keyboard navigation and Enter selects the highlighted folder", () => {
    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    const onSelect = vi.fn();
    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect,
    });

    const items = () =>
      Array.from(
        document.body.querySelectorAll(".rss-folder-selector-item"),
      ) as HTMLElement[];

    // Down selects second item
    document.dispatchEvent(new KeyboardEvent("keydown", { key: "ArrowDown" }));
    expect(items()[1].classList.contains("is-selected")).toBe(true);

    // Up wraps back to first
    document.dispatchEvent(new KeyboardEvent("keydown", { key: "ArrowUp" }));
    expect(items()[0].classList.contains("is-selected")).toBe(true);

    // Enter selects current
    document.dispatchEvent(new KeyboardEvent("keydown", { key: "Enter" }));
    expect(onSelect).toHaveBeenCalledWith("Alpha");
  });

  it("closes on Escape/Tab and on outside click", () => {
    vi.useFakeTimers();

    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    const onClose = vi.fn();
    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
      onClose,
    });

    // register click-outside handler
    vi.runAllTimers();

    document.dispatchEvent(new KeyboardEvent("keydown", { key: "Escape" }));
    expect(onClose).toHaveBeenCalledTimes(1);
    expect(
      document.body.querySelector(".rss-folder-selector-popup"),
    ).toBeNull();

    // reopen and test outside click
    onClose.mockClear();
    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
      onClose,
    });
    vi.runAllTimers();

    const outside = document.body.createDiv();
    outside.click();
    expect(onClose).toHaveBeenCalledTimes(1);
    expect(
      document.body.querySelector(".rss-folder-selector-popup"),
    ).toBeNull();

    // reopen and test Tab closes too
    onClose.mockClear();
    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect: () => {},
      onClose,
    });
    document.dispatchEvent(new KeyboardEvent("keydown", { key: "Tab" }));
    expect(onClose).toHaveBeenCalledTimes(1);
  });

  it("listOnly mode renders without input and does not show create option", () => {
    const anchorEl = document.body.createDiv();
    vi.spyOn(anchorEl, "getBoundingClientRect").mockReturnValue({
      left: 0,
      top: 0,
      bottom: 0,
      right: 0,
      width: 0,
      height: 0,
    } as DOMRect);

    const onSelect = vi.fn();
    new FolderSelectorPopup(createPluginStub(), {
      anchorEl,
      onSelect,
      listOnly: true,
    });

    expect(document.body.querySelector(".rss-folder-selector-input")).toBeNull();
    expect(
      document.body.querySelector(".rss-folder-selector-create"),
    ).toBeNull();

    document.dispatchEvent(new KeyboardEvent("keydown", { key: "Enter" }));
    expect(onSelect).toHaveBeenCalledWith("Alpha");
  });
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import {
  renderKeywordFilterEditor,
  type KeywordFilterEditorState,
} from "../../../src/components/keyword-filter-editor";
import type { KeywordFilterRule } from "../../../src/types/types";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

function createRule(overrides: Partial<KeywordFilterRule> = {}): KeywordFilterRule {
  return {
    id: "r1",
    type: "include",
    keyword: "alpha",
    matchMode: "partial",
    applyToTitle: true,
    applyToSummary: false,
    applyToContent: false,
    enabled: true,
    createdAt: 0,
    ...overrides,
  };
}

function setupEditor(initial: KeywordFilterEditorState, opts?: { showOverrideToggle?: boolean }) {
  const containerEl = document.body.createDiv();
  let state: KeywordFilterEditorState = initial;
  const onChange = vi.fn((next: KeywordFilterEditorState) => {
    state = next;
    render();
  });

  const render = () => {
    renderKeywordFilterEditor({
      containerEl,
      state,
      showOverrideToggle: opts?.showOverrideToggle,
      onChange,
    });
  };

  render();
  return { containerEl, getState: () => state, onChange };
}

beforeEach(() => {
  installObsidianDomPolyfills();
  document.body.empty();
  vi.restoreAllMocks();
});

describe("renderKeywordFilterEditor", () => {
  it("renders empty state and Add new rule appends a default rule", () => {
    const { getState } = setupEditor({ includeLogic: "AND", rules: [] });

    expect(document.body.querySelector(".rss-keyword-filter-empty")?.textContent).toContain(
      "No keyword rules configured",
    );

    const addBtn = document.body.querySelector(".rss-keyword-filter-add-btn") as HTMLButtonElement;
    expect(addBtn).toBeTruthy();

    vi.spyOn(Date, "now").mockReturnValue(123);
    vi.spyOn(Math, "random").mockReturnValue(0.42);

    addBtn.click();

    const state = getState();
    expect(state.rules).toHaveLength(1);
    expect(state.rules[0]).toMatchObject({
      type: "include",
      keyword: "",
      matchMode: "partial",
      applyToTitle: true,
      applyToSummary: true,
      applyToContent: true,
      applyToURL: false,
      enabled: true,
      createdAt: 123,
    });

    expect(document.body.querySelector(".rss-keyword-filter-rule-row")).toBeTruthy();
    expect(document.body.querySelector(".rss-keyword-filter-rule-title")?.textContent).toBe(
      "Rule 1",
    );
  });

  it("toggles include logic AND/OR via segmented buttons", () => {
    const { getState } = setupEditor({ includeLogic: "AND", rules: [createRule()] });

    const getBtns = () => {
      const andBtn = document.body.querySelector(
        '.rss-keyword-filter-logic-row [data-value="AND"]',
      ) as HTMLButtonElement;
      const orBtn = document.body.querySelector(
        '.rss-keyword-filter-logic-row [data-value="OR"]',
      ) as HTMLButtonElement;
      return { andBtn, orBtn };
    };

    expect(getBtns().andBtn.classList.contains("is-active")).toBe(true);
    expect(getBtns().orBtn.classList.contains("is-active")).toBe(false);

    getBtns().orBtn.click();
    expect(getState().includeLogic).toBe("OR");
    expect(getBtns().andBtn.classList.contains("is-active")).toBe(false);
    expect(getBtns().orBtn.classList.contains("is-active")).toBe(true);
  });

  it("supports override global rules toggle when enabled", () => {
    const { getState } = setupEditor(
      { includeLogic: "AND", rules: [], overrideGlobalRules: false },
      { showOverrideToggle: true },
    );

    const checkbox = document.body.querySelector(
      ".rss-keyword-filter-toggle-row input[type=checkbox]",
    ) as HTMLInputElement;
    expect(checkbox.checked).toBe(false);

    checkbox.checked = true;
    checkbox.dispatchEvent(new Event("change"));
    expect(getState().overrideGlobalRules).toBe(true);
  });

  it("edits a rule: type, match mode, keyword, and location toggles", () => {
    const { getState } = setupEditor({ includeLogic: "AND", rules: [createRule()] });

    const includeBtn = document.body.querySelector(
      '.rss-keyword-filter-rule-type-row [data-value="include"]',
    ) as HTMLButtonElement;
    const excludeBtn = document.body.querySelector(
      '.rss-keyword-filter-rule-type-row [data-value="exclude"]',
    ) as HTMLButtonElement;
    expect(includeBtn.classList.contains("is-active")).toBe(true);
    excludeBtn.click();
    expect(getState().rules[0].type).toBe("exclude");

    const exactBtn = document.body.querySelector(
      '.rss-keyword-filter-rule-match-row [data-value="exact"]',
    ) as HTMLButtonElement;
    exactBtn.click();
    expect(getState().rules[0].matchMode).toBe("exact");

    const input = document.body.querySelector(".rss-keyword-filter-input") as HTMLInputElement;
    input.value = "beta";
    input.dispatchEvent(new Event("change"));
    expect(getState().rules[0].keyword).toBe("beta");

    const summaryLabel = Array.from(
      document.body.querySelectorAll(".rss-keyword-filter-location-toggle label"),
    ).find((el) => el.textContent === "Summary") as HTMLLabelElement;
    expect(summaryLabel).toBeTruthy();
    summaryLabel.click();
    expect(getState().rules[0].applyToSummary).toBe(true);

      const urlLabel = Array.from(
      document.body.querySelectorAll(".rss-keyword-filter-location-toggle label"),
      ).find((el) => el.textContent === "URL") as HTMLLabelElement;
      expect(urlLabel).toBeTruthy();
      urlLabel.click();
      expect(getState().rules[0].applyToURL).toBe(true);
  });

  it("disables rule controls when a rule is disabled and delete removes rule", () => {
    const { getState } = setupEditor({ includeLogic: "AND", rules: [createRule()] });

    const enabledBtn = document.body.querySelector(
      ".rss-keyword-filter-enabled-btn",
    ) as HTMLButtonElement;
    enabledBtn.click();
    expect(getState().rules[0].enabled).toBe(false);

    const row = document.body.querySelector(".rss-keyword-filter-rule-row") as HTMLElement;
    expect(row.classList.contains("is-disabled")).toBe(true);

    const excludeBtn = document.body.querySelector(
      '.rss-keyword-filter-rule-type-row [data-value="exclude"]',
    ) as HTMLButtonElement;
    expect(excludeBtn.disabled).toBe(true);
    excludeBtn.click();
    expect(getState().rules[0].type).toBe("include");

    const deleteBtn = document.body.querySelector(
      ".rss-keyword-filter-delete-header",
    ) as HTMLButtonElement;
    deleteBtn.click();
    expect(getState().rules).toHaveLength(0);
    expect(document.body.querySelector(".rss-keyword-filter-empty")).toBeTruthy();
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";
import { createReaderFormatPortal } from "../../../src/utils/reader-format-portal";
import type { ReaderFormatSettings } from "../../../src/types/types";

installObsidianDomPolyfills();

function setMatchMedia(matches: boolean): void {
  window.matchMedia = ((query: string) => {
    return {
      matches,
      media: query,
      onchange: null,
      addListener: () => {
        // deprecated
      },
      removeListener: () => {
        // deprecated
      },
      addEventListener: () => {
        // no-op
      },
      removeEventListener: () => {
        // no-op
      },
      dispatchEvent: () => false,
    } as MediaQueryList;
  }) as typeof window.matchMedia;
}

function createFormat(overrides: Partial<ReaderFormatSettings> = {}): ReaderFormatSettings {
  return {
    textAlign: "justify",
    paragraphWidth: 100,
    fontScalePct: 100,
    lineHeightPct: 140,
    fontFamily: "default",
    paragraphSpacing: "default",
    ...overrides,
  };
}

describe("createReaderFormatPortal", () => {
  beforeEach(() => {
    document.body.innerHTML = "";
  });

  afterEach(() => {
    document.body.innerHTML = "";
  });

  it("creates a desktop portal and fires change callbacks", () => {
    setMatchMedia(false);

    const anchor = document.body.createDiv();
    const format = createFormat({ textAlign: "justify" });
    const defaults = createFormat();

    const applyFormat = vi.fn();
    const scheduleSave = vi.fn();
    const flushSave = vi.fn();
    const openReaderDisplaySettings = vi.fn();

    const handle = createReaderFormatPortal({
      anchor,
      format,
      defaults,
      applyFormat,
      scheduleSave,
      flushSave,
      openReaderDisplaySettings,
    });

    const portal = document.body.querySelector(".rss-reader-format-dropdown-portal");
    expect(portal).toBeTruthy();
    expect(document.body.querySelector(".rss-reader-format-sheet-backdrop")).toBeNull();

    expect(portal?.textContent).toContain("Theme default");
    expect(portal?.textContent).not.toContain("Font default");
    expect(portal?.textContent).not.toContain("Paragraph width");

    const fontScaleValue = portal?.querySelector(
      ".rss-reader-format-row[data-setting='fontScalePct'] .rss-reader-format-value",
    ) as HTMLElement | null;
    expect(fontScaleValue?.textContent).toBe("100%");

    const fontScaleIncrease = portal?.querySelector(
      ".rss-reader-format-row[data-setting='fontScalePct'] .rss-reader-format-stepper-increase",
    ) as HTMLElement | null;
    expect(fontScaleIncrease).toBeTruthy();
    fontScaleIncrease?.dispatchEvent(new MouseEvent("click", { bubbles: true }));

    expect(format.fontScalePct).toBe(110);
    expect(fontScaleValue?.textContent).toBe("110%");
    expect(applyFormat).toHaveBeenCalledTimes(1);
    expect(scheduleSave).toHaveBeenCalledTimes(1);

    const lineHeightDecrease = portal?.querySelector(
      ".rss-reader-format-row[data-setting='lineHeightPct'] .rss-reader-format-stepper-decrease",
    ) as HTMLElement | null;
    expect(lineHeightDecrease).toBeTruthy();
    lineHeightDecrease?.dispatchEvent(new MouseEvent("click", { bubbles: true }));

    expect(format.lineHeightPct).toBe(130);
    expect(applyFormat).toHaveBeenCalledTimes(2);
    expect(scheduleSave).toHaveBeenCalledTimes(2);

    const fontFamilyButtons = Array.from(
      portal?.querySelectorAll(".rss-reader-format-font-button") ?? [],
    ) as HTMLButtonElement[];
    expect(fontFamilyButtons.map((button) => button.textContent?.trim())).toEqual([
      "Theme default",
      "Serif",
      "Sans",
      "Mono",
    ]);

    const serifButton = fontFamilyButtons.find(
      (button) => button.dataset.value === "serif",
    );
    serifButton?.click();
    expect(format.fontFamily).toBe("serif");
    expect(applyFormat).toHaveBeenCalledTimes(3);
    expect(scheduleSave).toHaveBeenCalledTimes(3);

    const settingsButton = portal?.querySelector(
      ".rss-reader-format-settings-button",
    ) as HTMLElement | null;
    expect(settingsButton).toBeTruthy();
    settingsButton?.dispatchEvent(new MouseEvent("click", { bubbles: true }));
    expect(openReaderDisplaySettings).toHaveBeenCalledTimes(1);

    handle.close(true);
    expect(flushSave).toHaveBeenCalled();
    expect(document.body.querySelector(".rss-reader-format-dropdown-portal")).toBeNull();
  });

  it("resets the quick controls back to defaults", () => {
    setMatchMedia(false);

    const anchor = document.body.createDiv();
    const format = createFormat({
      fontScalePct: 150,
      lineHeightPct: 180,
      fontFamily: "mono",
    });
    const defaults = createFormat();

    const applyFormat = vi.fn();
    const scheduleSave = vi.fn();

    createReaderFormatPortal({
      anchor,
      format,
      defaults,
      applyFormat,
      scheduleSave,
      flushSave: vi.fn(),
      openReaderDisplaySettings: vi.fn(),
    });

    const portal = document.body.querySelector(".rss-reader-format-dropdown-portal");
    const resetButton = portal?.querySelector(
      ".rss-reader-format-reset-button",
    ) as HTMLElement | null;
    expect(resetButton).toBeTruthy();

    resetButton?.dispatchEvent(new MouseEvent("click", { bubbles: true }));

    expect(format.fontScalePct).toBe(defaults.fontScalePct);
    expect(format.lineHeightPct).toBe(defaults.lineHeightPct);
    expect(format.fontFamily).toBe(defaults.fontFamily);

    const fontScaleValue = portal?.querySelector(
      ".rss-reader-format-row[data-setting='fontScalePct'] .rss-reader-format-value",
    ) as HTMLElement | null;
    expect(fontScaleValue?.textContent).toBe("100%");

    const activeFontButton = portal?.querySelector(
      ".rss-reader-format-font-button.is-active",
    ) as HTMLElement | null;
    expect(activeFontButton?.textContent?.trim()).toBe("Theme default");
    expect(applyFormat).toHaveBeenCalledTimes(1);
    expect(scheduleSave).toHaveBeenCalledTimes(1);
  });

  it("creates a mobile sheet with backdrop and closes on backdrop click", () => {
    setMatchMedia(true);

    const anchor = document.body.createDiv();
    const format = createFormat();
    const defaults = createFormat();
    const flushSave = vi.fn();

    createReaderFormatPortal({
      anchor,
      format,
      defaults,
      applyFormat: vi.fn(),
      scheduleSave: vi.fn(),
      flushSave,
      openReaderDisplaySettings: vi.fn(),
    });

    expect(document.body.querySelector(".rss-reader-format-dropdown-portal")).toBeTruthy();
    const backdrop = document.body.querySelector(
      ".rss-reader-format-sheet-backdrop",
    ) as HTMLElement | null;
    expect(backdrop).toBeTruthy();

    backdrop?.dispatchEvent(new MouseEvent("click"));
    expect(flushSave).toHaveBeenCalled();
    expect(document.body.querySelector(".rss-reader-format-dropdown-portal")).toBeNull();
  });
});

import { vi, describe, it, expect, beforeEach, afterEach } from "vitest";
import { Sidebar, SidebarOptions, SidebarCallbacks } from "../../../src/components/sidebar";
import * as ObsidianStubs from "../../stubs/obsidian";
import type { App } from "../../stubs/obsidian";
import {
  RssDashboardSettings,
  Folder,
  type Feed,
} from "../../../src/types/types";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

installObsidianDomPolyfills();

describe("Sidebar Core", () => {
  let app: App;
  let container: HTMLElement;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let plugin: any;
  let settings: RssDashboardSettings;
  let options: SidebarOptions;
  let callbacks: SidebarCallbacks;

  beforeEach(() => {
    app = ObsidianStubs.App.createMock();
    container = document.createElement("div");
    
    settings = {
      feeds: [],
      folders: [],
      display: {
        sidebarRowSpacing: 10,
        sidebarRowIndentation: 20,
        sidebarItemPaddingLeft: 2,
        sidebarItemPaddingRight: 2,
      },
    } as unknown as RssDashboardSettings;

    options = {
      currentFolder: null,
      currentFeed: null,
      selectedTags: [],
      tagsCollapsed: true,
      collapsedFolders: [],
    };

    callbacks = {
      onFolderClick: vi.fn(),
      onFeedClick: vi.fn(),
      onTagToggle: vi.fn(),
      onClearTags: vi.fn(),
      onTagFilterModeChange: vi.fn(),
      onToggleTagsCollapse: vi.fn(),
      onToggleFolderCollapse: vi.fn(),
      onAddFolder: vi.fn(),
      onAddSubfolder: vi.fn(),
      onAddFeed: vi.fn(),
      onEditFeed: vi.fn(),
      onDeleteFeed: vi.fn(),
      onDeleteFolder: vi.fn(),
      onRefreshFeeds: vi.fn(),
      onUpdateFeed: vi.fn(),
      onImportOpml: vi.fn(),
      onExportOpml: vi.fn(),
      onToggleSidebar: vi.fn(),
    };

    plugin = {
      settings,
      saveSettings: vi.fn().mockResolvedValue(undefined),
    };
  });

  it("should initialize with correct properties", () => {
    const sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
    expect(sidebar).toBeDefined();
    // Accessing private members via bracket notation for testing
    expect(sidebar["app"]).toBe(app);
    expect(sidebar["container"]).toBe(container);
    expect(sidebar["settings"]).toBe(settings);
    expect(sidebar["options"]).toBe(options);
  });

  describe("extractDomain", () => {
    let sidebar: Sidebar;

    beforeEach(() => {
      sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
    });

    it("should extract domain from simple URL", () => {
      expect(sidebar["extractDomain"]("https://example.com/rss")).toBe("example.com");
    });

    it("should extract domain from URL with subdomains", () => {
      expect(sidebar["extractDomain"]("https://blog.example.com/feed")).toBe("example.com");
    });

    it("should handle feeds.feedburner.com specifically", () => {
      expect(sidebar["extractDomain"]("http://feeds.feedburner.com/test")).toBe("feedburner.com");
    });

    it("should handle invalid URLs gracefully", () => {
      expect(sidebar["extractDomain"]("not-a-url")).toBe("");
    });
  });

  describe("getFaviconUrl", () => {
    let sidebar: Sidebar;

    beforeEach(() => {
      sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
    });

    it("should return Google S2 favicon URL", () => {
      const domain = "example.com";
      const expected = `https://www.google.com/s2/favicons?sz=32&domain_url=http://${domain}`;
      expect(sidebar["getFaviconUrl"](domain)).toBe(expected);
    });

    it("should return empty string for empty domain", () => {
      expect(sidebar["getFaviconUrl"]("")).toBe("");
    });
  });

  describe("isFaviconUrlAvailable logic", () => {
    let sidebar: Sidebar;

    beforeEach(() => {
      sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      // Use vi.spyOn for mocking exported stub functions
      vi.spyOn(ObsidianStubs, "requestUrl").mockImplementation(async () => ({ status: 200, text: "" }));
    });

    afterEach(() => {
      vi.restoreAllMocks();
    });

    it("should return true for 200 OK headcount", async () => {
      vi.mocked(ObsidianStubs.requestUrl).mockResolvedValue({ status: 200, text: "" });
      const result = await sidebar["isFaviconUrlAvailable"]("http://fav.ico");
      expect(result).toBe(true);
      expect(ObsidianStubs.requestUrl).toHaveBeenCalledWith(expect.objectContaining({ method: "HEAD" }));
    });

    it("should retry with GET if HEAD returns 405", async () => {
      vi.mocked(ObsidianStubs.requestUrl)
        .mockResolvedValueOnce({ status: 405, text: "" })
        .mockResolvedValueOnce({ status: 200, text: "" });
        
      const result = await sidebar["isFaviconUrlAvailable"]("http://fav.ico");
      expect(result).toBe(true);
      expect(ObsidianStubs.requestUrl).toHaveBeenCalledTimes(2);
    });

    it("should return false if both HEAD and GET fail", async () => {
      vi.mocked(ObsidianStubs.requestUrl).mockRejectedValue(new Error("Network Error"));
      const result = await sidebar["isFaviconUrlAvailable"]("http://fav.ico");
      expect(result).toBe(false);
    });
  });

  describe("renderFallbackFeedIcon", () => {
    let sidebar: Sidebar;
    let iconEl: HTMLElement;

    beforeEach(() => {
      sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      iconEl = document.createElement("div");
    });

    it("should add rss icon by default", () => {
      sidebar["renderFallbackFeedIcon"](iconEl);
      expect(iconEl.dataset.icon).toBe("rss");
      expect(iconEl.classList.contains("rss-icon-hidden")).toBe(false);
    });

    it("should hide icon if setting enabled", () => {
      settings.display.hideDefaultRssIcon = true;
      sidebar["renderFallbackFeedIcon"](iconEl);
      expect(iconEl.classList.contains("rss-icon-hidden")).toBe(true);
    });
  });

  describe("Folder path caching", () => {
    let sidebar: Sidebar;

    beforeEach(() => {
      sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      settings.folders = [
        { name: "folder1", subfolders: [] },
        { name: "folder2", subfolders: [] },
      ] as Folder[];
    });

    it("should cache folder paths after first call", () => {
      expect(sidebar["cachedFolderPaths"]).toBeNull();
      const paths = sidebar["getCachedFolderPaths"]();
      expect(paths).toContain("folder1");
      expect(sidebar["cachedFolderPaths"]).not.toBeNull();
    });

    it("should clear cache when clearFolderPathCache is called", () => {
      sidebar["getCachedFolderPaths"]();
      sidebar.clearFolderPathCache();
      expect(sidebar["cachedFolderPaths"]).toBeNull();
    });
  });

  describe("renderHeader basics", () => {
    it("should render sidebar header container", () => {
      const sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      const headerSurface = container.createDiv();
      sidebar["renderHeader"](headerSurface);
      
      const header = headerSurface.querySelector(".rss-dashboard-sidebar-header");
      expect(header).toBeDefined();
    });
  });

  describe("lifecycle", () => {
    it("should disconnect resizeObserver on destroy", () => {
      const sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      const mockObserver = { disconnect: vi.fn() };
      sidebar["resizeObserver"] = mockObserver as any;
      
      sidebar.destroy();
      expect(mockObserver.disconnect).toHaveBeenCalled();
      expect(sidebar["resizeObserver"]).toBeNull();
    });
  });

  describe("refresh progress rendering", () => {
    function createFeed(overrides: Partial<Feed> = {}): Feed {
      return {
        title: "Feed A",
        url: "https://example.com/a.xml",
        folder: "",
        items: [],
        lastUpdated: 0,
        mediaType: "article",
        ...overrides,
      };
    }

    it("shows the all-feeds spinner and per-feed queued/processing indicators from plugin refresh state", () => {
      const processingFeed = createFeed({
        title: "Processing Feed",
        url: "https://example.com/processing.xml",
      });
      const queuedFeed = createFeed({
        title: "Queued Feed",
        url: "https://example.com/queued.xml",
      });

      settings.feeds = [processingFeed, queuedFeed];
      plugin.activeRefreshState = new Map([
        [processingFeed.url, { status: "processing", startedAt: Date.now() }],
        [queuedFeed.url, { status: "pending", startedAt: Date.now() }],
      ]);

      const sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      sidebar.render();

      const allFeedsIcon = container.querySelector(".rss-dashboard-all-feeds-icon");
      expect(allFeedsIcon?.classList.contains("refreshing")).toBe(true);

      const feedEls = Array.from(container.querySelectorAll(".rss-dashboard-feed"));
      const processingEl = feedEls.find((el) => el.getAttribute("data-feed-url") === processingFeed.url);
      const queuedEl = feedEls.find((el) => el.getAttribute("data-feed-url") === queuedFeed.url);

      expect(processingEl?.querySelector(".rss-dashboard-feed-icon")?.getAttribute("data-icon")).toBe("loader-2");
      expect(processingEl?.classList.contains("processing-feed")).toBe(true);
      expect(queuedEl?.querySelector(".rss-dashboard-feed-processing-indicator")?.textContent).toContain("ΓÅ│");
    });

    it("prefers import processing visuals over refresh visuals when both exist", () => {
      const feed = createFeed({
        title: "Imported Feed",
        url: "https://example.com/importing.xml",
      });

      settings.feeds = [feed];
      plugin.activeRefreshState = new Map([
        [feed.url, { status: "pending", startedAt: Date.now() }],
      ]);
      plugin.backgroundImportQueue = [
        {
          ...feed,
          importStatus: "processing",
        },
      ];

      const sidebar = new Sidebar(app as any, container, plugin, settings, options, callbacks);
      sidebar.render();

      const feedEl = container.querySelector(".rss-dashboard-feed");
      expect(feedEl?.querySelector(".rss-dashboard-feed-icon")?.getAttribute("data-icon")).toBe("loader-2");
      expect(feedEl?.querySelector(".rss-dashboard-feed-processing-indicator")).toBeNull();
    });
  });
});

import { describe, it, expect } from "vitest";
import {
