    },
  ])(
    "$label",
    async ({
      initialDuration,
      initialItems,
      selections,
      expectedDuration,
      expectedGuids,
    }) => {
      vi.spyOn(Date, "now").mockReturnValue(AUTO_DELETE_TEST_NOW_MS);

      const app = createMockApp();
      const feed: Feed = {
        title: "Old title",
        url: "https://example.com/old.xml",
