/**
 * Phase 2 (Red) ΓåÆ Phase 3 (Green) ΓÇö ImportExportService unit tests
 *
 * Covers:
 *   - getUserSettingsJson: omits feeds/folders/availableTags; produces valid JSON
 *   - showExportNotice: fires correct Notice for each result variant
 *   - showCopyNotice: fires correct Notice for copied/failed
 *   - exportOpml: calls exportBlob with a text/xml blob
 *   - exportDataJson: calls exportBlob with an application/json blob containing full settings
 */
import { describe, it, expect, vi, beforeEach } from "vitest";
import type { RssDashboardSettings } from "../../../src/types/types";

vi.mock("../../../src/utils/export-utils", () => ({
  exportBlob: vi.fn().mockResolvedValue("downloaded"),
  copyTextToClipboard: vi.fn().mockResolvedValue("copied"),
}));

vi.mock("../../../src/services/opml-manager", () => ({
  OpmlManager: {
    generateOpml: vi.fn().mockReturnValue("<opml>mock</opml>"),
  },
}));

import { ImportExportService } from "../../../src/services/import-export-service";
import { exportBlob } from "../../../src/utils/export-utils";

function makeSettings(overrides?: object): RssDashboardSettings {
  return {
    feeds: [{ url: "https://example.com/feed", name: "Test" }],
    folders: [{ name: "News", subfolders: [], createdAt: 0, modifiedAt: 0 }],
    availableTags: [{ name: "tech", color: "#fff" }],
    refreshInterval: 60,
    ...overrides,
  } as unknown as RssDashboardSettings;
}

function getNoticeMessages(spy: ReturnType<typeof vi.spyOn>): string[] {
  return spy.mock.calls
    .filter((call: unknown[]): call is [string, string] => call[0] === "[Stub Notice]")
    .map((call: [string, string]) => String(call[1]));
}

describe("ImportExportService", () => {
  let consoleLogSpy: ReturnType<typeof vi.spyOn>;

  beforeEach(() => {
    vi.clearAllMocks();
    consoleLogSpy = vi.spyOn(console, "log").mockImplementation(() => {});
  });

  describe("getUserSettingsJson", () => {
    it("omits feeds, folders, and availableTags from output", () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      const parsed = JSON.parse(svc.getUserSettingsJson());
      expect(parsed).not.toHaveProperty("feeds");
      expect(parsed).not.toHaveProperty("folders");
      expect(parsed).not.toHaveProperty("availableTags");
      expect(parsed).toHaveProperty("refreshInterval", 60);
    });

    it("produces valid JSON", () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      expect(() => JSON.parse(svc.getUserSettingsJson())).not.toThrow();
    });
  });

  describe("showExportNotice", () => {
    it('fires "Downloading <filename>" for "downloaded"', () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      svc.showExportNotice("downloaded", "data.json");
      expect(getNoticeMessages(consoleLogSpy)).toContain(
        "Downloading data.json",
      );
    });

    it('fires "Opened save menu for <filename>" for "shared"', () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      svc.showExportNotice("shared", "feeds.opml");
      expect(getNoticeMessages(consoleLogSpy)).toContain(
        "Opened save menu for feeds.opml",
      );
    });

    it('fires "Export canceled" for "canceled"', () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      svc.showExportNotice("canceled", "data.json");
      expect(getNoticeMessages(consoleLogSpy)).toContain("Export canceled");
    });

    it('fires "Unable to export <filename>" for "failed"', () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      svc.showExportNotice("failed", "data.json");
      expect(getNoticeMessages(consoleLogSpy)).toContain(
        "Unable to export data.json",
      );
    });
  });

  describe("showCopyNotice", () => {
    it('fires "Copied <filename> to clipboard" for "copied"', () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      svc.showCopyNotice("copied", "data.json");
      expect(getNoticeMessages(consoleLogSpy)).toContain(
        "Copied data.json to clipboard",
      );
    });

    it('fires "Unable to copy <filename>" for "failed"', () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      svc.showCopyNotice("failed", "data.json");
      expect(getNoticeMessages(consoleLogSpy)).toContain(
        "Unable to copy data.json",
      );
    });
  });

  describe("exportOpml", () => {
    it("calls exportBlob with a text/xml blob", async () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
      });
      await svc.exportOpml();
      expect(exportBlob).toHaveBeenCalledWith(
        expect.objectContaining({
          blob: expect.objectContaining({ type: "text/xml" }),
          filename: "feeds.opml",
        }),
      );
    });
  });

  describe("exportDataJson", () => {
    it("calls exportBlob with an application/json blob containing full settings", async () => {
      const settings = makeSettings();
      const svc = new ImportExportService({ settings, isMobile: false });
      await svc.exportDataJson();
      expect(exportBlob).toHaveBeenCalledWith(
        expect.objectContaining({
          blob: expect.objectContaining({ type: "application/json" }),
          filename: "data.json",
        }),
      );
      const call = vi.mocked(exportBlob).mock.calls[0][0];
      const text = await call.blob.text();
      const parsed = JSON.parse(text);
      expect(parsed).toHaveProperty("feeds");
    });
  });

  describe("exportPortableDataBundle", () => {
    it("exports a portable bundle JSON payload when a provider is supplied", async () => {
      const settings = makeSettings();
      const svc = new ImportExportService({
        settings,
        isMobile: false,
        getPortableDataBundle: () =>
          ({
            version: 1,
            exportedAt: 123,
            storageMode: "vault-shards",
            metadata: { ...settings, feeds: [] },
            shards: [],
            markdownMirrorFallbackPlanned: true,
          }) as any,
      });

      await svc.exportPortableDataBundle();

      expect(exportBlob).toHaveBeenCalledWith(
        expect.objectContaining({
          filename: "rss-dashboard-portable-bundle.json",
        }),
      );
      const call = vi.mocked(exportBlob).mock.calls[0][0];
      const text = await call.blob.text();
      const parsed = JSON.parse(text);
      expect(parsed.storageMode).toBe("vault-shards");
      expect(parsed.markdownMirrorFallbackPlanned).toBe(true);
    });
  });

  describe("importPortableDataBundleFromFile", () => {
    it("parses bundle JSON and passes it to the import callback", async () => {
      const importPortableDataBundle = vi.fn().mockResolvedValue(undefined);
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
        importPortableDataBundle,
      });

      const file = new File(
        [
          JSON.stringify({
            version: 1,
            exportedAt: 123,
            storageMode: "vault-shards",
            metadata: { feeds: [] },
            shards: [],
            markdownMirrorFallbackPlanned: true,
          }),
        ],
        "portable-bundle.json",
        { type: "application/json" },
      );

      await svc.importPortableDataBundleFromFile(file);

      expect(importPortableDataBundle).toHaveBeenCalledTimes(1);
      expect(importPortableDataBundle).toHaveBeenCalledWith(
        expect.objectContaining({
          version: 1,
          storageMode: "vault-shards",
        }),
      );
      expect(getNoticeMessages(consoleLogSpy)).toContain(
        "Portable data bundle imported",
      );
    });

    it("throws a helpful error when bundle JSON is invalid", async () => {
      const svc = new ImportExportService({
        settings: makeSettings(),
        isMobile: false,
        importPortableDataBundle: vi.fn().mockResolvedValue(undefined),
      });

      const file = new File(["{bad json"], "portable-bundle.json", {
        type: "application/json",
      });

      await expect(svc.importPortableDataBundleFromFile(file)).rejects.toThrow(
        "Invalid portable bundle JSON",
      );
    });
  });
});

import { describe, expect, it } from "vitest";
import { KeywordFilterService } from "../../../src/services/keyword-filter-service";
import type {
  Feed,
  FeedItem,
  GlobalKeywordRulesSettings,
  KeywordFilterRule,
  FeedKeywordRulesSettings,
} from "../../../src/types/types";

function createItem(overrides: Partial<FeedItem> = {}): FeedItem {
  return {
    title: "Hello World",
    link: "https://example.com/article",
    description: "<p>desc</p>",
    pubDate: "2024-01-01T00:00:00.000Z",
    guid: "guid-1",
    read: false,
    starred: false,
    tags: [],
    feedTitle: "Feed",
    feedUrl: "https://example.com/feed.xml",
    coverImage: "",
    ...overrides,
  };
}

function createRule(overrides: Partial<KeywordFilterRule> = {}): KeywordFilterRule {
  return {
    id: "r1",
    enabled: true,
    type: "include",
    keyword: "hello",
    matchMode: "partial",
    applyToTitle: true,
    applyToSummary: false,
    applyToContent: false,
    ...overrides,
  };
}

function createGlobalRules(
  overrides: Partial<GlobalKeywordRulesSettings> = {},
): GlobalKeywordRulesSettings {
  return {
    includeLogic: "AND",
    bypassAll: false,
    rules: [],
    ...overrides,
  };
}

function createFeedKeywordRules(
  overrides: Partial<FeedKeywordRulesSettings> = {},
): FeedKeywordRulesSettings {
  return {
    includeLogic: "AND",
    overrideGlobalRules: false,
    rules: [],
    ...overrides,
  };
}

function createFeed(overrides: Partial<Feed> = {}): Feed {
  return {
    title: "Feed",
    url: "https://example.com/feed.xml",
    folder: "Uncategorized",
    items: [],
    lastUpdated: 1,
    ...overrides,
  };
}

describe("KeywordFilterService.getActiveRules / hasActiveRules", () => {
  it("filters out disabled rules, blank keywords, and rules with no applyTo flags", () => {
    const rules: KeywordFilterRule[] = [
      createRule({ id: "enabled" }),
      createRule({ id: "disabled", enabled: false }),
      createRule({ id: "blank", keyword: "   " }),
      createRule({
        id: "noFlags",
        applyToTitle: false,
        applyToSummary: false,
        applyToContent: false,
      }),
    ];

    const active = KeywordFilterService.getActiveRules(rules);
    expect(active.map((r) => r.id)).toEqual(["enabled"]);
    expect(KeywordFilterService.hasActiveRules(rules)).toBe(true);
    expect(KeywordFilterService.hasActiveRules([rules[1], rules[2], rules[3]])).toBe(false);
  });
});

describe("KeywordFilterService.shouldApplyGlobalFilters", () => {
  it("applies global rules unless feed overrides them", () => {
    expect(KeywordFilterService.shouldApplyGlobalFilters(undefined)).toBe(true);
    expect(
      KeywordFilterService.shouldApplyGlobalFilters(
        createFeedKeywordRules({ overrideGlobalRules: false }),
      ),
    ).toBe(true);
    expect(
      KeywordFilterService.shouldApplyGlobalFilters(
        createFeedKeywordRules({ overrideGlobalRules: true }),
      ),
    ).toBe(false);
  });
});

describe("KeywordFilterService.evaluateRules", () => {
  it("returns true when there are no active rules", () => {
    const item = createItem();
    const rules = [
      createRule({ enabled: false }),
      createRule({ keyword: "   " }),
      createRule({
        applyToTitle: false,
        applyToSummary: false,
        applyToContent: false,
      }),
    ];

    expect(KeywordFilterService.evaluateRules(item, rules, "AND")).toBe(true);
  });

  it("enforces include rules with AND logic", () => {
    const item = createItem({ title: "alpha beta" });
    const rules = [
      createRule({ id: "a", type: "include", keyword: "alpha" }),
      createRule({ id: "b", type: "include", keyword: "beta" }),
    ];

    expect(KeywordFilterService.evaluateRules(item, rules, "AND")).toBe(true);
    expect(
      KeywordFilterService.evaluateRules(item, [rules[0], createRule({ keyword: "gamma" })], "AND"),
    ).toBe(false);
  });

  it("enforces include rules with OR logic", () => {
    const item = createItem({ title: "alpha" });
    const rules = [
      createRule({ id: "a", type: "include", keyword: "alpha" }),
      createRule({ id: "b", type: "include", keyword: "beta" }),
    ];

    expect(KeywordFilterService.evaluateRules(item, rules, "OR")).toBe(true);
  });

  it("exclude rules override includes when they match", () => {
    const item = createItem({ title: "alpha beta" });
    const rules = [
      createRule({ id: "inc", type: "include", keyword: "alpha" }),
      createRule({ id: "exc", type: "exclude", keyword: "beta" }),
    ];
    expect(KeywordFilterService.evaluateRules(item, rules, "AND")).toBe(false);
  });

  it("supports exact (word-boundary) matching and escapes regex characters", () => {
    const item = createItem({ title: "Concatenate cat C++ end." });
    const exactCat = createRule({ matchMode: "exact", keyword: "cat" });
    const exactCPlusPlus = createRule({ matchMode: "exact", keyword: "C++" });

    // exact "cat" should match standalone "cat" but not "Concatenate"
    expect(KeywordFilterService.evaluateRules(item, [exactCat], "AND")).toBe(true);

    const item2 = createItem({ title: "concatenate only" });
    expect(KeywordFilterService.evaluateRules(item2, [exactCat], "AND")).toBe(false);

    // "C++" should not blow up regex and should match
    expect(KeywordFilterService.evaluateRules(item, [exactCPlusPlus], "AND")).toBe(true);
  });

  it("uses summary/content fallbacks (summary/content ΓåÆ description) based on applyTo flags", () => {
    const item = createItem({
      title: "nope",
      description: "description has KEYWORD",
      summary: "",
      content: "",
    });

    const ruleSummary = createRule({
      keyword: "keyword",
      applyToTitle: false,
      applyToSummary: true,
      applyToContent: false,
      matchMode: "partial",
    });
    const ruleContent = createRule({
      keyword: "keyword",
      applyToTitle: false,
      applyToSummary: false,
      applyToContent: true,
      matchMode: "partial",
    });
    const ruleTitle = createRule({
      keyword: "keyword",
      applyToTitle: true,
      applyToSummary: false,
      applyToContent: false,
      matchMode: "partial",
    });

    expect(KeywordFilterService.evaluateRules(item, [ruleSummary], "AND")).toBe(true);
    expect(KeywordFilterService.evaluateRules(item, [ruleContent], "AND")).toBe(true);
    expect(KeywordFilterService.evaluateRules(item, [ruleTitle], "AND")).toBe(false);
  });

  it("can match against article links for URL-based feed filtering", () => {
    const shortItem = createItem({
      title: "Regular-looking title",
      link: "https://www.youtube.com/shorts/6PkQMo39mbI",
      description: "no marker here",
    });
    const watchItem = createItem({
      title: "Regular-looking title",
      link: "https://www.youtube.com/watch?v=rVepNd1TUew",
      description: "no marker here",
    });
    const rule = createRule({
      type: "exclude",
      keyword: "/shorts/",
      applyToTitle: false,
      applyToSummary: false,
      applyToContent: false,
      applyToURL: true,
    });

    expect(KeywordFilterService.evaluateRules(shortItem, [rule], "AND")).toBe(false);
    expect(KeywordFilterService.evaluateRules(watchItem, [rule], "AND")).toBe(true);
  });
});

describe("KeywordFilterService.evaluateForArticle", () => {
  it("bypasses all filters when global bypassAll is set", () => {
    const decision = KeywordFilterService.evaluateForArticle(
      createItem({ title: "anything" }),
      createFeed(),
      createGlobalRules({ bypassAll: true }),
    );
    expect(decision).toEqual({ included: true, excludedBy: "none" });
  });

  it("excludes by global when global rules fail", () => {
    const item = createItem({ title: "alpha" });
    const globalRules = createGlobalRules({
      rules: [createRule({ type: "include", keyword: "beta" })],
      includeLogic: "AND",
    });

    const decision = KeywordFilterService.evaluateForArticle(item, undefined, globalRules);
    expect(decision).toEqual({ included: false, excludedBy: "global" });
  });

  it("does not apply global rules when feed overrides them", () => {
    const item = createItem({ title: "alpha" });
    const feed = createFeed({
      keywordRules: createFeedKeywordRules({
        overrideGlobalRules: true,
        rules: [createRule({ type: "include", keyword: "alpha" })],
      }) as any,
    });
    const globalRules = createGlobalRules({
      rules: [createRule({ type: "include", keyword: "beta" })],
    });

    const decision = KeywordFilterService.evaluateForArticle(item, feed, globalRules);
    expect(decision).toEqual({ included: true, excludedBy: "none" });
  });

  it("excludes by feed when feed rules fail (after global passes)", () => {
    const item = createItem({ title: "alpha" });
    const feed = createFeed({
      keywordRules: createFeedKeywordRules({
        rules: [createRule({ type: "include", keyword: "beta" })],
      }),
    });
    const globalRules = createGlobalRules({
      rules: [createRule({ type: "include", keyword: "alpha" })],
    });

    const decision = KeywordFilterService.evaluateForArticle(item, feed, globalRules);
    expect(decision).toEqual({ included: false, excludedBy: "feed" });
  });
});

