  it("moves and appends after the last feed in the destination folder", () => {
    const settings = cloneSettings();
    settings.feeds = [
      makeFeed("A", "a", "Work"),
      makeFeed("B", "b", "Home"),
      makeFeed("C", "c", "Home"),
