});

describe("moveFolder", () => {
  it("rejects missing required inputs and invalid nesting", () => {
    const settings = cloneSettings();
    settings.folders = [folder("Alpha", [folder("Child")])];
    settings.feeds = [];

    expect(
      moveFolder(settings, { draggedPath: "", targetPath: "Alpha", placement: "before" }),
    ).toEqual({ ok: false, error: "Missing dragged folder path." });

    expect(
      moveFolder(settings, { draggedPath: "Alpha", targetPath: "", placement: "before" }),
    ).toEqual({ ok: false, error: "Missing target folder path." });

    expect(
      moveFolder(settings, { draggedPath: "Alpha", targetPath: "Alpha/Child", placement: "nest" }),
    ).toEqual({
      ok: false,
      error: "Cannot move a folder into itself or a descendant.",
    });
  });

  it("rejects when dragged or target folder is not found", () => {
    const settings = cloneSettings();
    settings.folders = [folder("Alpha"), folder("Beta")];
    settings.feeds = [];

    expect(
      moveFolder(settings, { draggedPath: "Missing", targetPath: "Beta", placement: "nest" }),
    ).toEqual({ ok: false, error: "Dragged folder not found." });

    expect(
      moveFolder(settings, { draggedPath: "Alpha", targetPath: "Missing", placement: "nest" }),
    ).toEqual({ ok: false, error: "Target folder not found." });
  });

  it("rejects duplicate sibling names at destination", () => {
    const settings = cloneSettings();
    settings.folders = [
      folder("Alpha"),
      folder("Beta", [folder("Alpha")]),
    ];
    settings.feeds = [];

    const result = moveFolder(settings, {
      draggedPath: "Alpha",
      targetPath: "Beta",
      placement: "nest",
    });

    expect(result.ok).toBe(false);
    expect(result.error).toContain('A folder named "Alpha" already exists');
  });

  it("moves within root and adjusts insertion index when moving forward", () => {
    const settings = cloneSettings();
    settings.folders = [folder("A"), folder("B"), folder("C")];
    settings.feeds = [];

    const result = moveFolder(settings, {
      draggedPath: "A",
      targetPath: "C",
      placement: "after",
    });

    expect(result.ok).toBe(true);
    expect(settings.folders.map((f) => f.name)).toEqual(["B", "C", "A"]);
    expect(settings.folderSortOrder?.by).toBe("custom");
    expect(result.newPath).toBe("A");
  });

  it("nests into target and remaps feeds + collapsedFolders + sort keys", () => {
    const settings = cloneSettings();
    settings.folders = [
      folder("Alpha", [folder("Child")]),
      folder("Beta"),
    ];
    settings.feeds = [
      makeFeed("Feed", "f", "Alpha/Child"),
      makeFeed("Other", "o", "Beta"),
    ];
    settings.collapsedFolders = ["Alpha", "Alpha/Child"];
    settings.folderFeedSortOrders = {
      "Alpha/Child": { by: "name", ascending: true } as any,
    };

    const result = moveFolder(settings, {
      draggedPath: "Alpha",
      targetPath: "Beta",
      placement: "nest",
    });

    expect(result.ok).toBe(true);
    expect(result.newPath).toBe("Beta/Alpha");
    expect(settings.feeds.find((f) => f.url === "f")?.folder).toBe("Beta/Alpha/Child");
    expect(settings.collapsedFolders).toEqual(["Beta/Alpha", "Beta/Alpha/Child"]);
    expect(settings.folderFeedSortOrders?.["Beta/Alpha/Child"]?.by).toBe("name");
    expect(settings.folderFeedSortOrders?.["Alpha/Child"]).toBeUndefined();
    expect(settings.folderSortOrder?.by).toBe("custom");
  });
});

import { App, type TFile } from "obsidian";
import { vi } from "vitest";
import { WebViewerIntegration } from "../../../src/services/web-viewer-integration";
import type { ArticleSavingSettings, FeedItem } from "../../../src/types/types";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

export interface WebViewerPluginStub {
  openWebpage?: (url: string, title: string) => Promise<void>;
  currentTitle?: string;
  currentUrl?: string;
  cleanedHtml?: string;
}

export interface WebViewerIntegrationHarnessOverrides {
  settings?: Partial<ArticleSavingSettings>;
  webViewerPlugin?: WebViewerPluginStub | null;
  webpageContainer?: HTMLElement | null;
}

function cloneDefaultSettings(): ArticleSavingSettings {
  return {
    addSavedTag: true,
    defaultFolder: "RSS articles/",
    defaultTemplate: "---\ntitle: {{title}}\n---\n\n{{content}}",
    includeFrontmatter: true,
    frontmatterTemplate: "",
    saveFullContent: true,
    fetchTimeout: 30_000,
    savedTemplates: [],
  };
}

export function buildFeedItem(overrides: Partial<FeedItem> = {}): FeedItem {
  const pubDate =
    overrides.pubDate ?? new Date("2026-01-01T00:00:00Z").toISOString();
  return {
    guid: overrides.guid ?? "guid",
    title: overrides.title ?? "Title",
    link: overrides.link ?? "https://example.com",
    pubDate,
    description: overrides.description ?? "<p>desc</p>",
    summary: overrides.summary ?? "Summary",
    author: overrides.author ?? "Author",
    read: overrides.read ?? false,
    starred: overrides.starred ?? false,
    saved: overrides.saved ?? false,
    tags: overrides.tags ?? [],
    feedTitle: overrides.feedTitle ?? "Feed",
    feedUrl: overrides.feedUrl ?? "https://example.com/feed",
    coverImage: overrides.coverImage ?? "",
  } as FeedItem;
}

export function createWebpageContainer(): HTMLElement {
  installObsidianDomPolyfills();
  return (document.body as unknown as HTMLElement).createDiv({
    cls: "webpage-container",
  });
}

export function createWebViewerIntegrationHarness(
  overrides: WebViewerIntegrationHarnessOverrides = {},
) {
  installObsidianDomPolyfills();

  const app = new App() as unknown as App & {
    plugins: { plugins: Record<string, unknown> };
  };

  const webViewerPlugin: WebViewerPluginStub | null =
    overrides.webViewerPlugin === undefined
      ? {
      openWebpage: vi.fn(async () => {}),
      currentTitle: "Web Title",
      currentUrl: "https://example.com",
      cleanedHtml: "<p>clean</p>",
    }
      : overrides.webViewerPlugin;

  app.plugins = {
    plugins: {
      ...(webViewerPlugin ? { "webpage-html-export": webViewerPlugin } : {}),
    },
  };

  const settings = cloneDefaultSettings();
  if (overrides.settings) {
    Object.assign(settings, overrides.settings);
  }

  const integration = new WebViewerIntegration(app as any, settings);

  const createdContainer = overrides.webpageContainer === undefined;
  const webpageContainer =
    overrides.webpageContainer === undefined ? createWebpageContainer() : overrides.webpageContainer;

  const cleanup = () => {
    if (createdContainer && webpageContainer) {
      webpageContainer.remove();
    }
  };

  return {
    app,
    settings,
    webViewerPlugin,
    webpageContainer,
    integration,
    // Helpers for tests that need to inspect vault effects.
    getFile: (path: string): TFile | null => app.vault.getAbstractFileByPath(path) as any,
    cleanup,
  };
}

