import { beforeEach, describe, expect, it, vi } from "vitest";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";
import { DEFAULT_SETTINGS, type RssDashboardSettings } from "../../../src/types/types";

function cloneSettings(): RssDashboardSettings {
  return JSON.parse(JSON.stringify(DEFAULT_SETTINGS)) as RssDashboardSettings;
}

function stubRect(rect: {
  top: number;
  left: number;
  bottom: number;
  right: number;
  width: number;
  height: number;
}): DOMRect {
  return rect as unknown as DOMRect;
}

describe("Startup filters settings popover positioning (integration)", () => {
  beforeEach(() => {
    installObsidianDomPolyfills();
    document.body.empty();
  });

  it("opens above when anchor is near bottom and follows scroll reposition", async () => {
    vi.useFakeTimers();
    // Drive rAF through timers for deterministic tests.
    vi.stubGlobal(
      "requestAnimationFrame",
      (cb: FrameRequestCallback) => window.setTimeout(() => cb(0), 0) as any,
    );

    const { renderDisplaySettingsTab } = await import(
      "../../../src/settings/tabs/display-settings-tab"
    );

    const container = document.body.createDiv();
    const settings = cloneSettings();

    // Minimal plugin mock
    const plugin = {
      settings,
      saveSettings: vi.fn(async () => {}),
      notifyFiltersUpdated: vi.fn(() => {}),
      getActiveDashboardView: vi.fn(async () => null),
      app: { workspace: { revealLeaf: vi.fn(async () => {}) } },
    };

    renderDisplaySettingsTab(container, plugin as never, () => {});

    const buttons = Array.from(container.querySelectorAll("button"));
    const startupBtn = buttons.find((b) => (b.textContent ?? "") === "All");
    expect(startupBtn).toBeTruthy();

    // Stub viewport size
    Object.defineProperty(window, "innerHeight", { value: 740, configurable: true });
    Object.defineProperty(window, "innerWidth", { value: 400, configurable: true });

    let anchorRect = {
      top: 700,
      bottom: 730,
      left: 20,
      right: 120,
      width: 100,
      height: 30,
    };
    (startupBtn as HTMLButtonElement).getBoundingClientRect = () =>
      stubRect(anchorRect);

    // Stub menu/submenu rects in jsdom (layout is 0 otherwise)
    const originalGetBoundingClientRect = HTMLElement.prototype.getBoundingClientRect;
    HTMLElement.prototype.getBoundingClientRect = function () {
      if (this.classList.contains("rss-dashboard-startup-filters-menu-portal")) {
        return stubRect({
          top: 0,
          left: 0,
          bottom: 200,
          right: 190,
          width: 190,
          height: 200,
        });
      }
      if (this.classList.contains("rss-dashboard-tag-submenu")) {
        return stubRect({
          top: 0,
          left: 0,
          bottom: 300,
          right: 150,
          width: 150,
          height: 300,
        });
      }
      return originalGetBoundingClientRect.call(this);
    };

    startupBtn?.dispatchEvent(new MouseEvent("click", { bubbles: true }));
    await vi.runAllTimersAsync();

    const portal = document.body.querySelector<HTMLElement>(
      ".rss-dashboard-startup-filters-menu-portal",
    );
    expect(portal).toBeTruthy();
    expect(parseFloat(portal?.style.top ?? "0")).toBeLessThan(anchorRect.top);

    const initialTop = portal?.style.top;

    // Simulate scroll moving the button upward in viewport coordinates
    anchorRect = {
      top: 500,
      bottom: 530,
      left: 20,
      right: 120,
      width: 100,
      height: 30,
    };
    document.dispatchEvent(new Event("scroll"));
    await vi.runAllTimersAsync();

    expect(portal?.style.top).not.toEqual(initialTop);

    // Restore prototype
    HTMLElement.prototype.getBoundingClientRect = originalGetBoundingClientRect;
    vi.useRealTimers();
  });

  it("positions tag submenu within viewport when opening Tagged submenu", async () => {
    vi.useFakeTimers();
    vi.stubGlobal(
      "requestAnimationFrame",
      (cb: FrameRequestCallback) => window.setTimeout(() => cb(0), 0) as any,
    );

    const { renderDisplaySettingsTab } = await import(
      "../../../src/settings/tabs/display-settings-tab"
    );

    const container = document.body.createDiv();
    const settings = cloneSettings();
    settings.availableTags = [{ name: "A", color: "#111111" }];

    const plugin = {
      settings,
      saveSettings: vi.fn(async () => {}),
      notifyFiltersUpdated: vi.fn(() => {}),
      getActiveDashboardView: vi.fn(async () => null),
      app: { workspace: { revealLeaf: vi.fn(async () => {}) } },
    };

    renderDisplaySettingsTab(container, plugin as never, () => {});

    const startupBtn = Array.from(container.querySelectorAll("button")).find(
      (b) => (b.textContent ?? "") === "All",
    ) as HTMLButtonElement | undefined;
    expect(startupBtn).toBeTruthy();

    Object.defineProperty(window, "innerHeight", { value: 260, configurable: true });
    Object.defineProperty(window, "innerWidth", { value: 260, configurable: true });

    startupBtn!.getBoundingClientRect = () =>
      stubRect({
        top: 200,
        bottom: 230,
        left: 200,
        right: 240,
        width: 40,
        height: 30,
      });

    const originalGetBoundingClientRect = HTMLElement.prototype.getBoundingClientRect;
    HTMLElement.prototype.getBoundingClientRect = function () {
      if (this.classList.contains("rss-dashboard-startup-filters-menu-portal")) {
        return stubRect({
          top: 0,
          left: 0,
          bottom: 200,
          right: 190,
          width: 190,
          height: 200,
        });
      }
      if (this.classList.contains("rss-dashboard-tag-submenu")) {
        // Force a too-tall submenu to require clamping.
        return stubRect({
          top: 0,
          left: 0,
          bottom: 500,
          right: 150,
          width: 150,
          height: 500,
        });
      }
      return originalGetBoundingClientRect.call(this);
    };

    startupBtn!.click();
    await vi.runAllTimersAsync();

    const taggedRow = Array.from(
      document.body.querySelectorAll<HTMLElement>(".rss-dashboard-filter-menu-item"),
    ).find((el) => (el.textContent ?? "").includes("Tagged"));
    expect(taggedRow).toBeTruthy();

    taggedRow!.dispatchEvent(new MouseEvent("mouseenter", { bubbles: true }));
    await vi.runAllTimersAsync();

    const submenu = document.body.querySelector<HTMLElement>(".rss-dashboard-tag-submenu");
    expect(submenu).toBeTruthy();

    const cssTop = submenu?.style.getPropertyValue("--submenu-top");
    const cssLeft = submenu?.style.getPropertyValue("--submenu-left");
    expect(cssTop).toBeTruthy();
    expect(cssLeft).toBeTruthy();

    const top = parseFloat(cssTop ?? "0");
    const left = parseFloat(cssLeft ?? "0");
    expect(top).toBeGreaterThanOrEqual(0);
    expect(left).toBeGreaterThanOrEqual(0);

    HTMLElement.prototype.getBoundingClientRect = originalGetBoundingClientRect;
    vi.useRealTimers();
  });
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import * as obsidian from "obsidian";
import { renderGeneralSettingsTab } from "../../../src/settings/tabs/general-settings-tab";
import {
  ShardDeletionFailureModal,
  StorageTransitionModal,
} from "../../../src/settings/modals/storage-settings-modals";
import { ShardFolderDeletionError } from "../../../src/services/feed-storage-repository";
import { DEFAULT_SETTINGS } from "../../../src/types/types";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

function cloneSettings() {
  return JSON.parse(JSON.stringify(DEFAULT_SETTINGS));
}

async function flushAsyncWork(cycles = 6) {
  for (let index = 0; index < cycles; index += 1) {
    await Promise.resolve();
  }
}

function resetDocumentBody(): void {
  document.body.innerHTML = "";
}

function createTestContainer(): HTMLDivElement {
  const containerEl = document.createElement("div");
  document.body.appendChild(containerEl);
  return containerEl;
}

function getSettingByName(containerEl: HTMLElement, name: string): HTMLElement {
  const settingEls = Array.from(containerEl.querySelectorAll(".setting-item"));
  const match = settingEls.find((el) => {
    const nameEl = el.querySelector(".setting-item-name");
    return nameEl?.textContent === name;
  });

  if (!match) {
    throw new Error(`Setting not found: ${name}`);
  }

  return match as HTMLElement;
}

function createPlugin() {
  return {
    app: obsidian.App.createMock(),
    settingTab: {
      display: vi.fn(),
    },
    settings: cloneSettings(),
    saveSettings: vi.fn(async () => {}),
    getActiveDashboardView: vi.fn(async () => null),
    getStorageStatus: vi.fn(() => ({
      mode: "legacy-json",
      folder: ".rss-dashboard-data/feeds",
      shardCount: 0,
      feedCount: 0,
      migrationReady: true,
      lastRepairResult: "Not yet run",
    })),
    migrateToVaultStorage: vi.fn(async () => {}),
    revertToLegacyJsonStorage: vi.fn(async () => {}),
    revertToLegacyJsonStorageWithOptions: vi.fn(async () => {}),
    isShardFolderDeletionError: (error: unknown) =>
      error instanceof ShardFolderDeletionError,
    openStorageFolderInSystem: vi.fn(async () => {}),
    repairVaultStorage: vi.fn(async () => {}),
    importPortableDataBundleFromFile: vi.fn(async () => {}),
    exportDataJson: vi.fn(async () => {}),
    exportPortableDataBundle: vi.fn(async () => {}),
  };
}

beforeEach(() => {
  installObsidianDomPolyfills();
  resetDocumentBody();
  vi.restoreAllMocks();
  vi.clearAllMocks();
});

describe("General settings storage section", () => {
  it("renders the experimental storage controls in the General tab", () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();

    renderGeneralSettingsTab(containerEl, plugin as any);

    expect(getSettingByName(containerEl, "Storage mode").textContent).toContain(
      "legacy monolithic data.json store",
    );
    expect(getSettingByName(containerEl, "Storage folder").textContent).toContain(
      "cross-device sync tools can access it",
    );
    expect(getSettingByName(containerEl, "Storage status").textContent).toContain(
      "Migration ready",
    );
  });

  it("applies the pending legacy-to-shards storage change through the modal", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();
    vi.spyOn(StorageTransitionModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(StorageTransitionModal.prototype, "waitForClose").mockResolvedValue(
      "apply",
    );

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageModeSetting = getSettingByName(containerEl, "Storage mode");
    const select = storageModeSetting.querySelector("select") as HTMLSelectElement;
    select.value = "vault-shards";
    select.dispatchEvent(new Event("change"));

    const buttons = Array.from(containerEl.querySelectorAll("button"));
    const applyButton = buttons.find(
      (button) => button.textContent === "Apply",
    ) as HTMLButtonElement;
    const repairButton = buttons.find(
      (button) => button.textContent === "Repair/Rebuild storage",
    ) as HTMLButtonElement;
    const importButton = buttons.find(
      (button) => button.textContent === "Import shard data",
    ) as HTMLButtonElement;
    const exportButton = buttons.find(
      (button) => button.textContent === "Export shard data",
    ) as HTMLButtonElement;

    applyButton.click();
    repairButton.click();
    importButton.click();
    exportButton.click();

    await Promise.resolve();

    expect(plugin.migrateToVaultStorage).toHaveBeenCalledTimes(1);
    expect(plugin.repairVaultStorage).toHaveBeenCalledTimes(1);
    expect(plugin.exportPortableDataBundle).toHaveBeenCalledTimes(1);
  });

  it("does not trigger migration when the storage mode dropdown changes", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageModeSetting = getSettingByName(containerEl, "Storage mode");
    const select = storageModeSetting.querySelector("select") as HTMLSelectElement;

    select.value = "vault-shards";
    select.dispatchEvent(new Event("change"));

    await Promise.resolve();

    expect(plugin.migrateToVaultStorage).not.toHaveBeenCalled();
    expect(plugin.revertToLegacyJsonStorage).not.toHaveBeenCalled();
    expect(select.value).toBe("vault-shards");
    expect(plugin.settings.storageMode).toBe("legacy-json");
  });

  it("exports data.json from the apply modal before migrating to shards", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();
    vi.spyOn(StorageTransitionModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(StorageTransitionModal.prototype, "waitForClose").mockResolvedValue(
      "export-data-json",
    );

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageModeSetting = getSettingByName(containerEl, "Storage mode");
    const select = storageModeSetting.querySelector("select") as HTMLSelectElement;
    select.value = "vault-shards";
    select.dispatchEvent(new Event("change"));

    const applyButton = Array.from(containerEl.querySelectorAll("button")).find(
      (button) => button.textContent === "Apply",
    ) as HTMLButtonElement;

    applyButton.click();
    await Promise.resolve();

    expect(plugin.exportDataJson).toHaveBeenCalledTimes(1);
    expect(plugin.migrateToVaultStorage).not.toHaveBeenCalled();
  });

  it("passes the delete-shard-folder choice when applying a shards-to-legacy change", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();
    plugin.settings.storageMode = "vault-shards";
    plugin.getStorageStatus = vi.fn(() => ({
      mode: "vault-shards",
      folder: ".rss-dashboard-data/feeds",
      shardCount: 3,
      feedCount: 3,
      migrationReady: false,
      lastRepairResult: "Migration completed",
    }));
    vi.spyOn(StorageTransitionModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(StorageTransitionModal.prototype, "waitForClose").mockResolvedValue(
      "apply-delete-shards",
    );

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageModeSetting = getSettingByName(containerEl, "Storage mode");
    const select = storageModeSetting.querySelector("select") as HTMLSelectElement;
    select.value = "legacy-json";
    select.dispatchEvent(new Event("change"));

    const applyButton = Array.from(containerEl.querySelectorAll("button")).find(
      (button) => button.textContent === "Apply",
    ) as HTMLButtonElement;

    applyButton.click();
    await Promise.resolve();

    expect(plugin.revertToLegacyJsonStorageWithOptions).toHaveBeenCalledWith({
      deleteShardFolder: true,
    });
  });

  it("pauses revert when shard deletion fails and can continue with apply anyway", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();
    plugin.settings.storageMode = "vault-shards";
    plugin.getStorageStatus = vi.fn(() => ({
      mode: "vault-shards",
      folder: ".rss-dashboard-data/feeds",
      shardCount: 3,
      feedCount: 3,
      migrationReady: false,
      lastRepairResult: "Migration completed",
    }));
    plugin.revertToLegacyJsonStorageWithOptions = vi
      .fn()
      .mockRejectedValueOnce(
        new ShardFolderDeletionError(
          ".rss-dashboard-data/feeds",
          "Shard folder still exists after delete attempt",
        ),
      )
      .mockResolvedValueOnce(undefined);

    vi.spyOn(StorageTransitionModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(StorageTransitionModal.prototype, "waitForClose").mockResolvedValue(
      "apply-delete-shards",
    );
    vi.spyOn(ShardDeletionFailureModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(ShardDeletionFailureModal.prototype, "waitForClose").mockResolvedValue(
      "apply-anyway",
    );

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageModeSetting = getSettingByName(containerEl, "Storage mode");
    const select = storageModeSetting.querySelector("select") as HTMLSelectElement;
    select.value = "legacy-json";
    select.dispatchEvent(new Event("change"));

    const applyButton = Array.from(containerEl.querySelectorAll("button")).find(
      (button) => button.textContent === "Apply",
    ) as HTMLButtonElement;

    applyButton.click();
    await flushAsyncWork();

    expect(plugin.revertToLegacyJsonStorageWithOptions).toHaveBeenNthCalledWith(1, {
      deleteShardFolder: true,
    });
    expect(plugin.revertToLegacyJsonStorageWithOptions).toHaveBeenNthCalledWith(2, {
      deleteShardFolder: false,
    });
  });

  it("can open the shard folder after delete failure before the user decides", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();
    plugin.settings.storageMode = "vault-shards";
    plugin.getStorageStatus = vi.fn(() => ({
      mode: "vault-shards",
      folder: ".rss-dashboard-data/feeds",
      shardCount: 3,
      feedCount: 3,
      migrationReady: false,
      lastRepairResult: "Migration completed",
    }));
    plugin.revertToLegacyJsonStorageWithOptions = vi
      .fn()
      .mockRejectedValueOnce(
        new ShardFolderDeletionError(
          ".rss-dashboard-data/feeds",
          "Shard folder still exists after delete attempt",
        ),
      );

    vi.spyOn(StorageTransitionModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(StorageTransitionModal.prototype, "waitForClose").mockResolvedValue(
      "apply-delete-shards",
    );
    vi.spyOn(ShardDeletionFailureModal.prototype, "open").mockImplementation(() => {});
    vi.spyOn(ShardDeletionFailureModal.prototype, "waitForClose")
      .mockResolvedValueOnce("open-folder")
      .mockResolvedValueOnce("cancel");

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageModeSetting = getSettingByName(containerEl, "Storage mode");
    const select = storageModeSetting.querySelector("select") as HTMLSelectElement;
    select.value = "legacy-json";
    select.dispatchEvent(new Event("change"));

    const applyButton = Array.from(containerEl.querySelectorAll("button")).find(
      (button) => button.textContent === "Apply",
    ) as HTMLButtonElement;

    applyButton.click();
    await flushAsyncWork();

    expect(plugin.openStorageFolderInSystem).toHaveBeenCalledWith(
      ".rss-dashboard-data/feeds",
    );
    expect(plugin.revertToLegacyJsonStorageWithOptions).toHaveBeenCalledTimes(1);
  });

  it("updates the storage folder setting through a standard text input", async () => {
    const containerEl = createTestContainer();
    const plugin = createPlugin();

    renderGeneralSettingsTab(containerEl, plugin as any);

    const storageFolderSetting = getSettingByName(containerEl, "Storage folder");
    const input = storageFolderSetting.querySelector("input") as HTMLInputElement;

    input.value = "RSS Mirror/Feeds";
    input.dispatchEvent(new Event("input"));

    await Promise.resolve();

    expect(plugin.settings.storageFolder).toBe("RSS Mirror/Feeds");
    expect(plugin.saveSettings).toHaveBeenCalledTimes(1);
