import { beforeEach, describe, expect, it, vi } from "vitest";
import * as obsidian from "obsidian";
import { DEFAULT_SETTINGS } from "../../../src/types/types";
import { renderTagsSettingsTab } from "../../../src/settings/tabs/tags-settings-tab";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

function flushPromises(): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, 0));
}

function getSettingByName(containerEl: HTMLElement, name: string): HTMLElement {
  const settingEls = Array.from(containerEl.querySelectorAll(".setting-item"));
  const match = settingEls.find((el) => {
    const nameEl = el.querySelector(".setting-item-name");
    return nameEl?.textContent === name;
  });
  if (!match) {
    throw new Error(`Setting not found: ${name}`);
  }
  return match as HTMLElement;
}

function cloneSettings(): typeof DEFAULT_SETTINGS {
  return JSON.parse(JSON.stringify(DEFAULT_SETTINGS));
}

beforeEach(() => {
  installObsidianDomPolyfills();
  document.body.empty();
  vi.restoreAllMocks();
});

describe("renderTagsSettingsTab()", () => {
  it("persists color changes, updates applied tags, and refreshes open tag views", async () => {
    const containerEl = document.body.createDiv();
    const settings = cloneSettings();
    settings.availableTags = [{ name: "tag1", color: "#000000" }];
    settings.feeds = [
      {
        name: "Feed 1",
        url: "https://example.com/feed.xml",
        folder: "",
        items: [
          {
            title: "Article 1",
            link: "https://example.com/article-1",
            pubDate: new Date().toISOString(),
            content: "",
            description: "",
            guid: "article-1",
            read: false,
            feedUrl: "https://example.com/feed.xml",
            feedTitle: "Feed 1",
            tags: [{ name: "tag1", color: "#000000" }],
          },
        ],
      } as any,
    ];

    const trigger = vi.fn();
    const plugin = {
      app: obsidian.App.createMock(),
      settings,
      saveSettings: vi.fn(async () => {}),
      refreshOpenTagColorViews: vi.fn(async () => {}),
    };

    (plugin.app.workspace as any).trigger = trigger;

    renderTagsSettingsTab(containerEl, plugin as any, vi.fn());

    const tagSetting = getSettingByName(containerEl, "tag1");
    const picker = tagSetting.querySelector(
      'input[type="color"]',
    ) as HTMLInputElement;
    picker.value = "#ff0000";
    picker.dispatchEvent(new Event("input"));
    await flushPromises();

    expect(plugin.settings.availableTags[0].color).toBe("#ff0000");
    expect(plugin.settings.feeds[0].items[0].tags?.[0].color).toBe("#ff0000");
    expect(plugin.saveSettings).toHaveBeenCalledTimes(1);
    expect(plugin.refreshOpenTagColorViews).toHaveBeenCalledTimes(1);
    expect(trigger).toHaveBeenCalledWith("rss-dashboard:tags-mutated");
  });

  it("deletes an existing tag and refreshes", async () => {
    const containerEl = document.body.createDiv();
    const settings = cloneSettings();
    settings.availableTags = [{ name: "tag1", color: "#000000" }];
    const onRefresh = vi.fn();

    const plugin = {
      app: obsidian.App.createMock(),
      settings,
      saveSettings: vi.fn(async () => {}),
      getActiveDashboardView: vi.fn(async () => null),
    };

    renderTagsSettingsTab(containerEl, plugin as any, onRefresh);

    const deleteBtn = containerEl.querySelector(
      'button[data-icon="trash"]',
    ) as HTMLButtonElement;
    deleteBtn.click();
    await flushPromises();

    expect(plugin.settings.availableTags).toHaveLength(0);
    expect(plugin.saveSettings).toHaveBeenCalledTimes(1);
    expect(onRefresh).toHaveBeenCalledTimes(1);
  });

  it("adds a new tag and refreshes", async () => {
    const containerEl = document.body.createDiv();
    const settings = cloneSettings();
    settings.availableTags = [];
    const onRefresh = vi.fn();

    const plugin = {
      app: obsidian.App.createMock(),
      settings,
      saveSettings: vi.fn(async () => {}),
      getActiveDashboardView: vi.fn(async () => null),
    };

    renderTagsSettingsTab(containerEl, plugin as any, onRefresh);

    const tagNameSetting = getSettingByName(containerEl, "Tag name");
    const nameInput = tagNameSetting.querySelector(
      'input[type="text"]',
    ) as HTMLInputElement;
    nameInput.value = "newTag";
    nameInput.dispatchEvent(new Event("input"));

    const tagColorSetting = getSettingByName(containerEl, "Tag color");
    const colorInput = tagColorSetting.querySelector(
      'input[type="color"]',
    ) as HTMLInputElement;
    colorInput.value = "#123456";
    colorInput.dispatchEvent(new Event("input"));

    const addBtn = Array.from(containerEl.querySelectorAll("button")).find(
      (b) => b.textContent === "Add tag",
    ) as HTMLButtonElement;
    addBtn.click();
    await flushPromises();

    expect(plugin.settings.availableTags).toHaveLength(1);
    expect(plugin.settings.availableTags[0]).toEqual({
      name: "newTag",
      color: "#123456",
    });
    expect(plugin.saveSettings).toHaveBeenCalledTimes(1);
    expect(onRefresh).toHaveBeenCalledTimes(1);
  });
});

export function installObsidianDomPolyfills(): void {
  const proto = HTMLElement.prototype as unknown as Record<string, unknown>;

  if (typeof window.matchMedia !== "function") {
    window.matchMedia = ((query: string) => {
      return {
        matches: false,
        media: query,
        onchange: null,
        addListener: () => {
          // deprecated
        },
        removeListener: () => {
          // deprecated
        },
        addEventListener: () => {
          // no-op
        },
        removeEventListener: () => {
          // no-op
        },
        dispatchEvent: () => false,
      } as MediaQueryList;
    }) as typeof window.matchMedia;
  }

  if (typeof proto.empty !== "function") {
    proto.empty = function empty(this: HTMLElement): void {
      this.textContent = "";
      while (this.firstChild) {
        this.removeChild(this.firstChild);
      }
    };
  }

  if (typeof (proto as any).setText !== "function") {
    (proto as any).setText = function (this: HTMLElement, text: string): void {
      this.textContent = text;
    };
  }

  if (typeof proto.addClass !== "function") {
    proto.addClass = function addClass(
      this: HTMLElement,
      ...classes: string[]
    ): void {
      this.classList.add(...classes);
    };
  }

  if (typeof (proto as any).addClasses !== "function") {
    (proto as any).addClasses = function addClasses(
      this: HTMLElement,
      classes: string[],
    ): void {
      this.classList.add(...classes);
    };
  }

  if (typeof proto.removeClass !== "function") {
    proto.removeClass = function removeClass(
      this: HTMLElement,
      ...classes: string[]
    ): void {
      this.classList.remove(...classes);
    };
  }

  if (typeof (proto as any).hasClass !== "function") {
    (proto as any).hasClass = function (
      this: HTMLElement,
      cls: string,
    ): boolean {
      return this.classList.contains(cls);
    };
  }

  if (typeof proto.toggleClass !== "function") {
    proto.toggleClass = function toggleClass(
      this: HTMLElement,
      cls: string,
      force?: boolean,
    ): void {
      this.classList.toggle(cls, force);
    };
  }

  if (typeof proto.setAttr !== "function") {
    proto.setAttr = function setAttr(
      this: HTMLElement,
      key: string,
      value: string,
    ): void {
      this.setAttribute(key, value);
    };
  }

  if (typeof (proto as any).getAttr !== "function") {
    (proto as any).getAttr = function (
      this: HTMLElement,
      key: string,
    ): string | null {
      return this.getAttribute(key);
    };
  }

  if (typeof proto.createDiv !== "function") {
    proto.createDiv = function createDiv(
      this: HTMLElement,
      opts?:
        | string
        | { cls?: string; text?: string; attr?: Record<string, string> },
    ): HTMLDivElement {
      const el = document.createElement("div");
      if (typeof opts === "string") {
        el.className = opts;
      } else {
        if (opts?.cls) el.className = opts.cls;
        if (opts?.text !== undefined) el.textContent = opts.text;
        if (opts?.attr) {
          Object.entries(opts.attr).forEach(([k, v]) => el.setAttribute(k, v));
        }
      }
      this.appendChild(el);
      return el;
    };
  }

  if (typeof proto.createSpan !== "function") {
    proto.createSpan = function createSpan(
      this: HTMLElement,
      opts?:
        | string
        | { cls?: string; text?: string; attr?: Record<string, string> },
    ): HTMLSpanElement {
      const el = document.createElement("span");
      if (typeof opts === "string") {
        el.className = opts;
      } else {
        if (opts?.cls) el.className = opts.cls;
        if (opts?.text !== undefined) el.textContent = opts.text;
        if (opts?.attr) {
          Object.entries(opts.attr).forEach(([k, v]) => el.setAttribute(k, v));
        }
      }
      this.appendChild(el);
      return el;
    };
  }

  if (typeof (proto as any).appendText !== "function") {
    (proto as any).appendText = function appendText(
      this: HTMLElement,
      text: string,
    ): void {
      this.append(document.createTextNode(text));
    };
  }

  if (typeof proto.createEl !== "function") {
    proto.createEl = function createEl<K extends keyof HTMLElementTagNameMap>(
      this: HTMLElement,
      tag: K,
      opts?: {
        cls?: string;
        text?: string;
        attr?: Record<string, string>;
        // Obsidian's createEl supports passing through common element props (e.g. value/placeholder).
        // Keep this permissive so unit tests behave like plugin runtime.
        // eslint-disable-next-line @typescript-eslint/no-explicit-any -- permissive type for polyfill matching runtime Obsidian createEl behaviour
        [key: string]: any;
      },
    ): HTMLElementTagNameMap[K] {
      const el = document.createElement(tag);
      if (opts?.cls) el.className = opts.cls;
      if (opts?.text !== undefined) el.textContent = opts.text;
      if (opts?.attr) {
        Object.entries(opts.attr).forEach(([k, v]) => el.setAttribute(k, v));
      }
      if (opts) {
        Object.entries(opts).forEach(([key, value]) => {
          if (key === "cls" || key === "text" || key === "attr") return;
          if (tag === "input" && key === "type" && typeof value === "string") {
            (el as unknown as HTMLInputElement).type = value;
            return;
          }
          // Pass through common properties like value/placeholder/disabled/etc.
          if (key in el) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any -- permissive type for polyfill matching runtime Obsidian createEl behaviour
            (el as any)[key] = value;
          }
        });
      }
      this.appendChild(el);
      return el;
    };
  }

  if (typeof Element.prototype.scrollIntoView !== "function") {
    Element.prototype.scrollIntoView = function scrollIntoView(): void {
      // no-op for jsdom
    };
  }

  if (typeof window.ResizeObserver !== "function") {
    class MockResizeObserver {
      observe(): void {}
      unobserve(): void {}
      disconnect(): void {}
    }
    (window as any).ResizeObserver = MockResizeObserver;
  }
}

export function installMediaElementPolyfills(): void {
  HTMLMediaElement.prototype.play = function play(
    this: HTMLMediaElement,
  ): Promise<void> {
    this.dispatchEvent(new Event("play"));
    return Promise.resolve();
  };

  HTMLMediaElement.prototype.pause = function pause(
    this: HTMLMediaElement,
  ): void {
    this.dispatchEvent(new Event("pause"));
  };

  HTMLMediaElement.prototype.load = function load(): void {
    // no-op for jsdom
  };
}

import { describe, expect, it, vi } from "vitest";
