      expect(changed).toBe(true);
      expect(feeds[0].items).toHaveLength(1);
      expect(feeds[0].items[0].content).toBe("Much longer body content");
    });

    it("merges tags without duplicates", async () => {
      const { dedupeAndNormalizeFeedItems } =
