              ],
            }),
          ],
        }),
      ];

      dedupeAndNormalizeFeedItems(feeds);

      const tags = feeds[0].items[0].tags ?? [];
      const tagNames = tags.map((t: any) => t.name);
      expect(tagNames).toContain("tech");
      expect(tagNames).toContain("news");
      expect(tagNames.filter((n: string) => n === "tech")).toHaveLength(1);
    });

    it("sorts items newest-first", async () => {
      const { dedupeAndNormalizeFeedItems } =
        await import("../../../src/utils/settings-loader");

      const feeds: Feed[] = [
        createFeed({
          items: [
            createFeedItem({
              guid: "old",
              title: "Old",
              link: "https://example.com/old",
              pubDate: "Mon, 01 Jan 2024 00:00:00 GMT",
            }),
            createFeedItem({
              guid: "new",
              title: "New",
              link: "https://example.com/new",
              pubDate: "Mon, 01 Apr 2024 00:00:00 GMT",
            }),
          ],
        }),
      ];

      dedupeAndNormalizeFeedItems(feeds);

      expect(feeds[0].items[0].guid).toBe("new");
      expect(feeds[0].items[1].guid).toBe("old");
    });

    it("canonicalizes item GUIDs via canonicalizeItemIdentityUrl", async () => {
      const { canonicalizeItemIdentityUrl } =
        await import("../../../src/utils/url-utils");
      (
        canonicalizeItemIdentityUrl as ReturnType<typeof vi.fn>
      ).mockImplementation((url: string) => url.replace(/^https?:/, "https:"));
      const { dedupeAndNormalizeFeedItems } =
        await import("../../../src/utils/settings-loader");

      const feeds: Feed[] = [
        createFeed({
          items: [
            createFeedItem({
              guid: "http://example.com/item",
              title: "Item",
              link: "http://example.com/item",
            }),
          ],
        }),
      ];

      dedupeAndNormalizeFeedItems(feeds);

      expect(feeds[0].items[0].guid).toBe("https://example.com/item");
    });

    it("merges YouTube duplicate entries (yt:video: vs watch URL vs shorts URL) on startup", async () => {
      // Regression test: shards can contain paired duplicates for the same
      // YouTube video stored under different GUID forms. dedupeAndNormalizeFeedItems
      // must collapse them to a single item using the canonical yt:video: key,
      // merging read/starred state from both entries.
      const { canonicalizeItemIdentityUrl } =
        await import("../../../src/utils/url-utils");

      // Mock canonicalizeItemIdentityUrl to perform YouTube normalisation so this
      // test exercises the deduplication logic without depending on the full
      // url-utils implementation (unit isolation).
      const YT_VIDEO_ID_RE = /^[-_A-Za-z0-9]{11}$/;
      (
        canonicalizeItemIdentityUrl as ReturnType<typeof vi.fn>
      ).mockImplementation((id: string): string => {
        if (id.startsWith("yt:video:")) {
          const videoId = id.slice("yt:video:".length);
          return YT_VIDEO_ID_RE.test(videoId) ? `yt:video:${videoId}` : id;
        }
        try {
          const u = new URL(id);
          const host = u.hostname.toLowerCase();
          if (
            host === "www.youtube.com" ||
            host === "youtube.com" ||
            host === "m.youtube.com"
          ) {
            const v = u.searchParams.get("v");
            if (v && YT_VIDEO_ID_RE.test(v)) return `yt:video:${v}`;
            const m = u.pathname.match(
              /^\/shorts\/([-_A-Za-z0-9]{11})(?:[/?#]|$)/,
            );
            if (m) return `yt:video:${m[1]}`;
          }
        } catch {
          // not a URL
        }
        return id;
      });

      const { dedupeAndNormalizeFeedItems } =
        await import("../../../src/utils/settings-loader");

      const feeds: Feed[] = [
        createFeed({
          items: [
            // Older entry ΓÇô URL form guid, user has read this one
            createFeedItem({
              guid: "https://www.youtube.com/shorts/4slngTaicg8",
              title: "60% of people have a drinking problem",
              link: "https://www.youtube.com/shorts/4slngTaicg8",
              read: true,
              starred: false,
              pubDate: "2026-05-12 18:11:59",
            }),
            // Duplicate entry ΓÇô yt:video form from a different parsing path
            createFeedItem({
              guid: "yt:video:4slngTaicg8",
              title: "60% of people have a drinking problem",
              link: "https://www.youtube.com/shorts/4slngTaicg8",
              read: false,
              starred: false,
              pubDate: "2026-05-12T18:11:59+00:00",
            }),
          ],
        }),
      ];

      const changed = dedupeAndNormalizeFeedItems(feeds);

      expect(changed).toBe(true);
      expect(feeds[0].items).toHaveLength(1);
      // Canonical guid must be the yt:video: form
      expect(feeds[0].items[0].guid).toBe("yt:video:4slngTaicg8");
      // read state must be merged (true | false = true)
      expect(feeds[0].items[0].read).toBe(true);
    });

    it("merges three YouTube entries for the same video (watch, shorts, yt:video) to one", async () => {
      // Edge case: a feed might accumulate all three GUID forms for one video.
      const { canonicalizeItemIdentityUrl } =
        await import("../../../src/utils/url-utils");

      const YT_VIDEO_ID_RE = /^[-_A-Za-z0-9]{11}$/;
      (
        canonicalizeItemIdentityUrl as ReturnType<typeof vi.fn>
      ).mockImplementation((id: string): string => {
        if (id.startsWith("yt:video:")) {
          const videoId = id.slice("yt:video:".length);
          return YT_VIDEO_ID_RE.test(videoId) ? `yt:video:${videoId}` : id;
        }
        try {
          const u = new URL(id);
          const host = u.hostname.toLowerCase();
          if (
            host === "www.youtube.com" ||
            host === "youtube.com" ||
            host === "m.youtube.com"
          ) {
            const v = u.searchParams.get("v");
            if (v && YT_VIDEO_ID_RE.test(v)) return `yt:video:${v}`;
            const m = u.pathname.match(
              /^\/shorts\/([-_A-Za-z0-9]{11})(?:[/?#]|$)/,
            );
            if (m) return `yt:video:${m[1]}`;
          }
        } catch {
          // not a URL
        }
        return id;
      });

      const { dedupeAndNormalizeFeedItems } =
        await import("../../../src/utils/settings-loader");

      const feeds: Feed[] = [
        createFeed({
          items: [
            createFeedItem({
              guid: "https://www.youtube.com/watch?v=dQw4w9WgXcQ",
              starred: true,
            }),
            createFeedItem({
              guid: "https://www.youtube.com/shorts/dQw4w9WgXcQ",
              read: true,
            }),
            createFeedItem({ guid: "yt:video:dQw4w9WgXcQ" }),
          ],
        }),
      ];

      dedupeAndNormalizeFeedItems(feeds);

      expect(feeds[0].items).toHaveLength(1);
      expect(feeds[0].items[0].guid).toBe("yt:video:dQw4w9WgXcQ");
      expect(feeds[0].items[0].read).toBe(true);
      expect(feeds[0].items[0].starred).toBe(true);
    });
  });
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import {
  applyAutomaticArticleTags,
  showEditTagModal,
  updateTagInSettings,
  withSavedTagName,
} from "../../../src/utils/tag-utils";
import { installObsidianDomPolyfills } from "../test-dom-polyfills";

type TestTag = { name: string; color?: string };

function makeSettings(tags: TestTag[]): any {
  return {
    availableTags: [...tags],
    feeds: [
      {
        items: [
          { title: "a", tags: [{ name: tags[0].name, color: tags[0].color }] },
          { title: "b", tags: [{ name: "other" }] },
          { title: "c" },
        ],
      },
    ],
  };
}

beforeEach(() => {
  installObsidianDomPolyfills();
  document.body.empty();
  vi.restoreAllMocks();
});

describe("tag-utils.updateTagInSettings", () => {
  it("updates availableTags and cascades changes into feed item tags", () => {
    const oldTag: TestTag = { name: "Tech", color: "#111111" };
    const settings = makeSettings([oldTag, { name: "News", color: "#222222" }]);

    const updated = updateTagInSettings(
      settings,
      oldTag as any,
      {
        name: "Technology",
        color: "#abcdef",
      } as any,
    );

    expect(updated).toEqual([
      { name: "Technology", color: "#abcdef" },
      { name: "News", color: "#222222" },
    ]);

    // Mutates settings.availableTags in-place (live reference).
    expect(settings.availableTags).toEqual(updated);

    expect(settings.feeds[0].items[0].tags).toEqual([
      { name: "Technology", color: "#abcdef" },
    ]);
    expect(settings.feeds[0].items[1].tags).toEqual([{ name: "other" }]);
    expect(settings.feeds[0].items[2].tags).toBeUndefined();
  });
});

describe("tag-utils.showEditTagModal", () => {
  it("validates empty and duplicate names, then saves and closes", async () => {
    const consoleSpy = vi.spyOn(console, "log").mockImplementation(() => {});

    const settings = makeSettings([
      { name: "Tech", color: "#111111" },
      { name: "News", color: "#222222" },
    ]);
    const tag = settings.availableTags[0];

    const onSave = vi.fn().mockResolvedValue(undefined);
    showEditTagModal({ settings, tag, onSave });

    const modal = document.querySelector(
      ".rss-dashboard-modal",
    ) as HTMLElement | null;
    expect(modal).not.toBeNull();

    const nameInput = document.querySelector(
      ".rss-dashboard-tag-modal-name-input",
    ) as HTMLInputElement | null;
    expect(nameInput).not.toBeNull();

    const saveButton = document.querySelector(
      "button.rss-dashboard-primary-button",
    ) as HTMLButtonElement | null;
    expect(saveButton).not.toBeNull();

    // Empty name
    nameInput!.value = "   ";
    saveButton!.click();
    expect(consoleSpy).toHaveBeenCalledWith(
      "[Stub Notice]",
      "Please enter a tag name!",
    );
    expect(document.querySelector(".rss-dashboard-modal")).not.toBeNull();

    // Duplicate (case-insensitive, and not same tag ref)
    nameInput!.value = "news";
    saveButton!.click();
    expect(consoleSpy).toHaveBeenCalledWith(
      "[Stub Notice]",
      "A tag with this name already exists!",
    );
    expect(document.querySelector(".rss-dashboard-modal")).not.toBeNull();

    // Success
    nameInput!.value = "Technology";
    saveButton!.click();
    await new Promise((r) => setTimeout(r, 0));

    expect(onSave).toHaveBeenCalledTimes(1);
    expect(settings.availableTags[0].name).toBe("Technology");
    expect(settings.feeds[0].items[0].tags[0].name).toBe("Technology");
    expect(document.querySelector(".rss-dashboard-modal")).toBeNull();
    expect(consoleSpy).toHaveBeenCalledWith(
      "[Stub Notice]",
      'Tag "Technology" updated successfully!',
    );
  });
});

describe("tag-utils.applyAutomaticArticleTags", () => {
  it("adds a canonical Favorite tag when an article is starred", () => {
    const article = {
      starred: false,
      tags: [{ name: "news", color: "#111111" }],
    } as any;

    const updates = applyAutomaticArticleTags(article, { starred: true }, {
      availableTags: [{ name: "Favorite", color: "#f1c40f" }],
      articleSaving: { addSavedTag: true },
    } as any);

    expect(updates.tags).toEqual([
      { name: "news", color: "#111111" },
      { name: "Favorite", color: "#f1c40f" },
    ]);
  });

  it("removes the canonical Favorite tag when an article is unstarred", () => {
    const article = {
      starred: true,
      tags: [
        { name: "Favorite", color: "#f1c40f" },
        { name: "news", color: "#111111" },
      ],
    } as any;

    const updates = applyAutomaticArticleTags(article, { starred: false }, {
      availableTags: [{ name: "Favorite", color: "#f1c40f" }],
      articleSaving: { addSavedTag: true },
    } as any);

    expect(updates.tags).toEqual([{ name: "news", color: "#111111" }]);
  });

  it("normalizes an existing lowercase saved tag when saving", () => {
    const article = {
      saved: false,
      tags: [{ name: "saved", color: "#123456" }],
    } as any;

    const updates = applyAutomaticArticleTags(article, { saved: true }, {
      availableTags: [],
      articleSaving: { addSavedTag: true },
    } as any);

    expect(updates.tags).toEqual([{ name: "Saved", color: "#123456" }]);
  });
});

describe("tag-utils.withSavedTagName", () => {
  it("appends Saved when missing and normalizes lowercase variants", () => {
    expect(withSavedTagName(["tech"])).toEqual(["tech", "Saved"]);
    expect(withSavedTagName(["tech", "saved"])).toEqual(["tech", "Saved"]);
  });
});

