function makeFeed(
  url: string,
  folder = "",
  items: Partial<FeedItem>[] = [],
): Feed {
  return {
    title: `Feed (${url})`,
    url,
    folder,
    items: items.map((i, idx) => ({
      title: `Item ${idx}`,
      link: `${url}#${idx}`,
      description: "",
      pubDate: new Date(Date.now() - idx * 1000).toISOString(),
      guid: `${url}#${idx}`,
      read: false,
      starred: false,
      tags: [],
      feedTitle: `Feed (${url})`,
      feedUrl: url,
      coverImage: "",
      ...i,
    })),
    lastUpdated: Date.now(),
  };
}

